var VERSES_LEVITICUS=[{"ref":"Leviticus 1:1","short":"Lev 1:1","text":"The LORD called Moses and spoke to him from the tent of meeting, saying,","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":1},{"ref":"Leviticus 1:2","short":"Lev 1:2","text":"“Speak to the people of Israel and say to them, When any one of you brings an offering to the LORD, you shall bring your offering of livestock from the herd or from the flock.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":2},{"ref":"Leviticus 1:3","short":"Lev 1:3","text":"“If his offering is a burnt offering from the herd, he shall offer a male without blemish. He shall bring it to the entrance of the tent of meeting, that he may be accepted before the LORD.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":3},{"ref":"Leviticus 1:4","short":"Lev 1:4","text":"He shall lay his hand on the head of the burnt offering, and it shall be accepted for him to make atonement for him.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":4},{"ref":"Leviticus 1:5","short":"Lev 1:5","text":"Then he shall kill the bull before the LORD, and Aaron’s sons the priests shall bring the blood and throw the blood against the sides of the altar that is at the entrance of the tent of meeting.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":5},{"ref":"Leviticus 1:6","short":"Lev 1:6","text":"Then he shall flay the burnt offering and cut it into pieces,","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":6},{"ref":"Leviticus 1:7","short":"Lev 1:7","text":"and the sons of Aaron the priest shall put fire on the altar and arrange wood on the fire.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":7},{"ref":"Leviticus 1:8","short":"Lev 1:8","text":"And Aaron’s sons the priests shall arrange the pieces, the head, and the fat, on the wood that is on the fire on the altar;","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":8},{"ref":"Leviticus 1:9","short":"Lev 1:9","text":"but its entrails and its legs he shall wash with water. And the priest shall burn all of it on the altar, as a burnt offering, a food offering with a pleasing aroma to the LORD.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":9},{"ref":"Leviticus 1:10","short":"Lev 1:10","text":"“If his gift for a burnt offering is from the flock, from the sheep or goats, he shall bring a male without blemish,","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":10},{"ref":"Leviticus 1:11","short":"Lev 1:11","text":"and he shall kill it on the north side of the altar before the LORD, and Aaron’s sons the priests shall throw its blood against the sides of the altar.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":11},{"ref":"Leviticus 1:12","short":"Lev 1:12","text":"And he shall cut it into pieces, with its head and its fat, and the priest shall arrange them on the wood that is on the fire on the altar,","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":12},{"ref":"Leviticus 1:13","short":"Lev 1:13","text":"but the entrails and the legs he shall wash with water. And the priest shall offer all of it and burn it on the altar; it is a burnt offering, a food offering with a pleasing aroma to the LORD.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":13},{"ref":"Leviticus 1:14","short":"Lev 1:14","text":"“If his offering to the LORD is a burnt offering of birds, then he shall bring his offering of turtledoves or pigeons.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":14},{"ref":"Leviticus 1:15","short":"Lev 1:15","text":"And the priest shall bring it to the altar and wring off its head and burn it on the altar. Its blood shall be drained out on the side of the altar.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":15},{"ref":"Leviticus 1:16","short":"Lev 1:16","text":"He shall remove its crop with its contents and cast it beside the altar on the east side, in the place for ashes.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":16},{"ref":"Leviticus 1:17","short":"Lev 1:17","text":"He shall tear it open by its wings, but shall not sever it completely. And the priest shall burn it on the altar, on the wood that is on the fire. It is a burnt offering, a food offering with a pleasing aroma to the LORD.","url":"ot/leviticus/Leviticus_1.html","book":"Leviticus","ch":1,"v":17},{"ref":"Leviticus 2:1","short":"Lev 2:1","text":"“When anyone brings a grain offering as an offering to the LORD, his offering shall be of fine flour. He shall pour oil on it and put frankincense on it","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":1},{"ref":"Leviticus 2:2","short":"Lev 2:2","text":"and bring it to Aaron’s sons the priests. And he shall take from it a handful of the fine flour and oil, with all of its frankincense, and the priest shall burn this as its memorial portion on the altar, a food offering with a pleasing aroma to the LORD.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":2},{"ref":"Leviticus 2:3","short":"Lev 2:3","text":"But the rest of the grain offering shall be for Aaron and his sons; it is a most holy part of the LORD’s food offerings.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":3},{"ref":"Leviticus 2:4","short":"Lev 2:4","text":"“When you bring a grain offering baked in the oven as an offering, it shall be unleavened loaves of fine flour mixed with oil or unleavened wafers smeared with oil.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":4},{"ref":"Leviticus 2:5","short":"Lev 2:5","text":"And if your offering is a grain offering baked on a griddle, it shall be of fine flour unleavened, mixed with oil.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":5},{"ref":"Leviticus 2:6","short":"Lev 2:6","text":"You shall break it in pieces and pour oil on it; it is a grain offering.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":6},{"ref":"Leviticus 2:7","short":"Lev 2:7","text":"And if your offering is a grain offering cooked in a pan, it shall be made of fine flour with oil.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":7},{"ref":"Leviticus 2:8","short":"Lev 2:8","text":"And you shall bring the grain offering that is made of these things to the LORD, and when it is presented to the priest, he shall bring it to the altar.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":8},{"ref":"Leviticus 2:9","short":"Lev 2:9","text":"And the priest shall take from the grain offering its memorial portion and burn this on the altar, a food offering with a pleasing aroma to the LORD.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":9},{"ref":"Leviticus 2:10","short":"Lev 2:10","text":"But the rest of the grain offering shall be for Aaron and his sons; it is a most holy part of the LORD’s food offerings.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":10},{"ref":"Leviticus 2:11","short":"Lev 2:11","text":"“No grain offering that you bring to the LORD shall be made with leaven, for you shall burn no leaven nor any honey as a food offering to the LORD.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":11},{"ref":"Leviticus 2:12","short":"Lev 2:12","text":"As an offering of firstfruits you may bring them to the LORD, but they shall not be offered on the altar for a pleasing aroma.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":12},{"ref":"Leviticus 2:13","short":"Lev 2:13","text":"You shall season all your grain offerings with salt. You shall not let the salt of the covenant with your God be missing from your grain offering; with all your offerings you shall offer salt.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":13},{"ref":"Leviticus 2:14","short":"Lev 2:14","text":"“If you offer a grain offering of firstfruits to the LORD, you shall offer for the grain offering of your firstfruits fresh ears, roasted with fire, crushed new grain.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":14},{"ref":"Leviticus 2:15","short":"Lev 2:15","text":"And you shall put oil on it and lay frankincense on it; it is a grain offering.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":15},{"ref":"Leviticus 2:16","short":"Lev 2:16","text":"And the priest shall burn as its memorial portion some of the crushed grain and some of the oil with all of its frankincense; it is a food offering to the LORD.","url":"ot/leviticus/Leviticus_2.html","book":"Leviticus","ch":2,"v":16},{"ref":"Leviticus 3:1","short":"Lev 3:1","text":"“If his offering is a sacrifice of peace offering, if he offers an animal from the herd, male or female, he shall offer it without blemish before the LORD.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":1},{"ref":"Leviticus 3:2","short":"Lev 3:2","text":"And he shall lay his hand on the head of his offering and kill it at the entrance of the tent of meeting, and Aaron’s sons the priests shall throw the blood against the sides of the altar.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":2},{"ref":"Leviticus 3:3","short":"Lev 3:3","text":"And from the sacrifice of the peace offering, as a food offering to the LORD, he shall offer the fat covering the entrails and all the fat that is on the entrails,","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":3},{"ref":"Leviticus 3:4","short":"Lev 3:4","text":"and the two kidneys with the fat that is on them at the loins, and the long lobe of the liver that he shall remove with the kidneys.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":4},{"ref":"Leviticus 3:5","short":"Lev 3:5","text":"Then Aaron’s sons shall burn it on the altar on top of the burnt offering, which is on the wood on the fire; it is a food offering with a pleasing aroma to the LORD.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":5},{"ref":"Leviticus 3:6","short":"Lev 3:6","text":"“If his offering for a sacrifice of peace offering to the LORD is an animal from the flock, male or female, he shall offer it without blemish.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":6},{"ref":"Leviticus 3:7","short":"Lev 3:7","text":"If he offers a lamb for his offering, then he shall offer it before the LORD,","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":7},{"ref":"Leviticus 3:8","short":"Lev 3:8","text":"lay his hand on the head of his offering, and kill it in front of the tent of meeting; and Aaron’s sons shall throw its blood against the sides of the altar.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":8},{"ref":"Leviticus 3:9","short":"Lev 3:9","text":"Then from the sacrifice of the peace offering he shall offer as a food offering to the LORD its fat; he shall remove the whole fat tail, cut off close to the backbone, and the fat that covers the entrails and all the fat that is on the entrails","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":9},{"ref":"Leviticus 3:10","short":"Lev 3:10","text":"and the two kidneys with the fat that is on them at the loins and the long lobe of the liver that he shall remove with the kidneys.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":10},{"ref":"Leviticus 3:11","short":"Lev 3:11","text":"And the priest shall burn it on the altar as a food offering to the LORD.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":11},{"ref":"Leviticus 3:12","short":"Lev 3:12","text":"“If his offering is a goat, then he shall offer it before the LORD","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":12},{"ref":"Leviticus 3:13","short":"Lev 3:13","text":"and lay his hand on its head and kill it in front of the tent of meeting, and the sons of Aaron shall throw its blood against the sides of the altar.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":13},{"ref":"Leviticus 3:14","short":"Lev 3:14","text":"Then he shall offer from it, as his offering for a food offering to the LORD, the fat covering the entrails and all the fat that is on the entrails","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":14},{"ref":"Leviticus 3:15","short":"Lev 3:15","text":"and the two kidneys with the fat that is on them at the loins and the long lobe of the liver that he shall remove with the kidneys.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":15},{"ref":"Leviticus 3:16","short":"Lev 3:16","text":"And the priest shall burn them on the altar as a food offering with a pleasing aroma. All fat is the LORD’s.","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":16},{"ref":"Leviticus 3:17","short":"Lev 3:17","text":"It shall be a statute forever throughout your generations, in all your dwelling places, that you eat neither fat nor blood.”","url":"ot/leviticus/Leviticus_3.html","book":"Leviticus","ch":3,"v":17},{"ref":"Leviticus 4:1","short":"Lev 4:1","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":1},{"ref":"Leviticus 4:2","short":"Lev 4:2","text":"“Speak to the people of Israel, saying, If anyone sins unintentionally in any of the LORD’s commandments about things not to be done, and does any one of them,","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":2},{"ref":"Leviticus 4:3","short":"Lev 4:3","text":"if it is the anointed priest who sins, thus bringing guilt on the people, then he shall offer for the sin that he has committed a bull from the herd without blemish to the LORD for a sin offering.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":3},{"ref":"Leviticus 4:4","short":"Lev 4:4","text":"He shall bring the bull to the entrance of the tent of meeting before the LORD and lay his hand on the head of the bull and kill the bull before the LORD.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":4},{"ref":"Leviticus 4:5","short":"Lev 4:5","text":"And the anointed priest shall take some of the blood of the bull and bring it into the tent of meeting,","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":5},{"ref":"Leviticus 4:6","short":"Lev 4:6","text":"and the priest shall dip his finger in the blood and sprinkle part of the blood seven times before the LORD in front of the veil of the sanctuary.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":6},{"ref":"Leviticus 4:7","short":"Lev 4:7","text":"And the priest shall put some of the blood on the horns of the altar of fragrant incense before the LORD that is in the tent of meeting, and all the rest of the blood of the bull he shall pour out at the base of the altar of burnt offering that is at the entrance of the tent of meeting.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":7},{"ref":"Leviticus 4:8","short":"Lev 4:8","text":"And all the fat of the bull of the sin offering he shall remove from it, the fat that covers the entrails and all the fat that is on the entrails","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":8},{"ref":"Leviticus 4:9","short":"Lev 4:9","text":"and the two kidneys with the fat that is on them at the loins and the long lobe of the liver that he shall remove with the kidneys","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":9},{"ref":"Leviticus 4:10","short":"Lev 4:10","text":"(just as these are taken from the ox of the sacrifice of the peace offerings); and the priest shall burn them on the altar of burnt offering.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":10},{"ref":"Leviticus 4:11","short":"Lev 4:11","text":"But the skin of the bull and all its flesh, with its head, its legs, its entrails, and its dung—","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":11},{"ref":"Leviticus 4:12","short":"Lev 4:12","text":"all the rest of the bull—he shall carry outside the camp to a clean place, to the ash heap, and shall burn it up on a fire of wood. On the ash heap it shall be burned up.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":12},{"ref":"Leviticus 4:13","short":"Lev 4:13","text":"“If the whole congregation of Israel sins unintentionally and the thing is hidden from the eyes of the assembly, and they do any one of the things that by the LORD’s commandments ought not to be done, and they realize their guilt,","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":13},{"ref":"Leviticus 4:14","short":"Lev 4:14","text":"when the sin which they have committed becomes known, the assembly shall offer a bull from the herd for a sin offering and bring it in front of the tent of meeting.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":14},{"ref":"Leviticus 4:15","short":"Lev 4:15","text":"And the elders of the congregation shall lay their hands on the head of the bull before the LORD, and the bull shall be killed before the LORD.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":15},{"ref":"Leviticus 4:16","short":"Lev 4:16","text":"Then the anointed priest shall bring some of the blood of the bull into the tent of meeting,","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":16},{"ref":"Leviticus 4:17","short":"Lev 4:17","text":"and the priest shall dip his finger in the blood and sprinkle it seven times before the LORD in front of the veil.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":17},{"ref":"Leviticus 4:18","short":"Lev 4:18","text":"And he shall put some of the blood on the horns of the altar that is in the tent of meeting before the LORD, and the rest of the blood he shall pour out at the base of the altar of burnt offering that is at the entrance of the tent of meeting.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":18},{"ref":"Leviticus 4:19","short":"Lev 4:19","text":"And all its fat he shall take from it and burn on the altar.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":19},{"ref":"Leviticus 4:20","short":"Lev 4:20","text":"Thus shall he do with the bull. As he did with the bull of the sin offering, so shall he do with this. And the priest shall make atonement for them, and they shall be forgiven.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":20},{"ref":"Leviticus 4:21","short":"Lev 4:21","text":"And he shall carry the bull outside the camp and burn it up as he burned the first bull; it is the sin offering for the assembly.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":21},{"ref":"Leviticus 4:22","short":"Lev 4:22","text":"“When a leader sins, doing unintentionally any one of all the things that by the commandments of the LORD his God ought not to be done, and realizes his guilt,","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":22},{"ref":"Leviticus 4:23","short":"Lev 4:23","text":"or the sin which he has committed is made known to him, he shall bring as his offering a goat, a male without blemish,","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":23},{"ref":"Leviticus 4:24","short":"Lev 4:24","text":"and shall lay his hand on the head of the goat and kill it in the place where they kill the burnt offering before the LORD; it is a sin offering.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":24},{"ref":"Leviticus 4:25","short":"Lev 4:25","text":"Then the priest shall take some of the blood of the sin offering with his finger and put it on the horns of the altar of burnt offering and pour out the rest of its blood at the base of the altar of burnt offering.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":25},{"ref":"Leviticus 4:26","short":"Lev 4:26","text":"And all its fat he shall burn on the altar, like the fat of the sacrifice of peace offerings. So the priest shall make atonement for him for his sin, and he shall be forgiven.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":26},{"ref":"Leviticus 4:27","short":"Lev 4:27","text":"“If anyone of the common people sins unintentionally in doing any one of the things that by the LORD’s commandments ought not to be done, and realizes his guilt,","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":27},{"ref":"Leviticus 4:28","short":"Lev 4:28","text":"or the sin which he has committed is made known to him, he shall bring for his offering a goat, a female without blemish, for his sin which he has committed.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":28},{"ref":"Leviticus 4:29","short":"Lev 4:29","text":"And he shall lay his hand on the head of the sin offering and kill the sin offering in the place of burnt offering.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":29},{"ref":"Leviticus 4:30","short":"Lev 4:30","text":"And the priest shall take some of its blood with his finger and put it on the horns of the altar of burnt offering and pour out all the rest of its blood at the base of the altar.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":30},{"ref":"Leviticus 4:31","short":"Lev 4:31","text":"And all its fat he shall remove, as the fat is removed from the peace offerings, and the priest shall burn it on the altar for a pleasing aroma to the LORD. And the priest shall make atonement for him, and he shall be forgiven.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":31},{"ref":"Leviticus 4:32","short":"Lev 4:32","text":"“If he brings a lamb as his offering for a sin offering, he shall bring a female without blemish","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":32},{"ref":"Leviticus 4:33","short":"Lev 4:33","text":"and lay his hand on the head of the sin offering and kill it for a sin offering in the place where they kill the burnt offering.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":33},{"ref":"Leviticus 4:34","short":"Lev 4:34","text":"Then the priest shall take some of the blood of the sin offering with his finger and put it on the horns of the altar of burnt offering and pour out all the rest of its blood at the base of the altar.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":34},{"ref":"Leviticus 4:35","short":"Lev 4:35","text":"And all its fat he shall remove as the fat of the lamb is removed from the sacrifice of peace offerings, and the priest shall burn it on the altar, on top of the LORD’s food offerings. And the priest shall make atonement for him for the sin which he has committed, and he shall be forgiven.","url":"ot/leviticus/Leviticus_4.html","book":"Leviticus","ch":4,"v":35},{"ref":"Leviticus 5:1","short":"Lev 5:1","text":"“If anyone sins in that he hears a public adjuration to testify, and though he is a witness, whether he has seen or come to know the matter, yet does not speak, he shall bear his iniquity;","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":1},{"ref":"Leviticus 5:2","short":"Lev 5:2","text":"or if anyone touches an unclean thing, whether a carcass of an unclean wild animal or a carcass of unclean livestock or a carcass of unclean swarming things, and it is hidden from him and he has become unclean, and he realizes his guilt;","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":2},{"ref":"Leviticus 5:3","short":"Lev 5:3","text":"or if he touches human uncleanness, of whatever sort the uncleanness may be with which one becomes unclean, and it is hidden from him, when he comes to know it, and realizes his guilt;","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":3},{"ref":"Leviticus 5:4","short":"Lev 5:4","text":"or if anyone utters with his lips a rash oath to do evil or to do good, any sort of rash oath that people swear, and it is hidden from him, when he comes to know it, and he realizes his guilt in any of these;","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":4},{"ref":"Leviticus 5:5","short":"Lev 5:5","text":"when he realizes his guilt in any of these and confesses the sin he has committed,","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":5},{"ref":"Leviticus 5:6","short":"Lev 5:6","text":"he shall bring to the LORD as his compensation for the sin that he has committed, a female from the flock, a lamb or a goat, for a sin offering. And the priest shall make atonement for him for his sin.","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":6},{"ref":"Leviticus 5:7","short":"Lev 5:7","text":"“But if he cannot afford a lamb, then he shall bring to the LORD as his compensation for the sin that he has committed two turtledoves or two pigeons, one for a sin offering and the other for a burnt offering.","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":7},{"ref":"Leviticus 5:8","short":"Lev 5:8","text":"He shall bring them to the priest, who shall offer first the one for the sin offering. He shall wring its head from its neck but shall not sever it completely,","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":8},{"ref":"Leviticus 5:9","short":"Lev 5:9","text":"and he shall sprinkle some of the blood of the sin offering on the side of the altar, while the rest of the blood shall be drained out at the base of the altar; it is a sin offering.","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":9},{"ref":"Leviticus 5:10","short":"Lev 5:10","text":"Then he shall offer the second for a burnt offering according to the rule. And the priest shall make atonement for him for the sin that he has committed, and he shall be forgiven.","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":10},{"ref":"Leviticus 5:11","short":"Lev 5:11","text":"“But if he cannot afford two turtledoves or two pigeons, then he shall bring as his offering for the sin that he has committed a tenth of an ephah of fine flour for a sin offering. He shall put no oil on it and shall put no frankincense on it, for it is a sin offering.","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":11},{"ref":"Leviticus 5:12","short":"Lev 5:12","text":"And he shall bring it to the priest, and the priest shall take a handful of it as its memorial portion and burn this on the altar, on the LORD’s food offerings; it is a sin offering.","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":12},{"ref":"Leviticus 5:13","short":"Lev 5:13","text":"Thus the priest shall make atonement for him for the sin which he has committed in any one of these things, and he shall be forgiven. And the remainder shall be for the priest, as in the grain offering.”","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":13},{"ref":"Leviticus 5:14","short":"Lev 5:14","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":14},{"ref":"Leviticus 5:15","short":"Lev 5:15","text":"“If anyone commits a breach of faith and sins unintentionally in any of the holy things of the LORD, he shall bring to the LORD as his compensation, a ram without blemish out of the flock, valued in silver shekels, according to the shekel of the sanctuary, for a guilt offering.","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":15},{"ref":"Leviticus 5:16","short":"Lev 5:16","text":"He shall also make restitution for what he has done amiss in the holy thing and shall add a fifth to it and give it to the priest. And the priest shall make atonement for him with the ram of the guilt offering, and he shall be forgiven.","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":16},{"ref":"Leviticus 5:17","short":"Lev 5:17","text":"“If anyone sins, doing any of the things that by the LORD’s commandments ought not to be done, though he did not know it, then realizes his guilt, he shall bear his iniquity.","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":17},{"ref":"Leviticus 5:18","short":"Lev 5:18","text":"He shall bring to the priest a ram without blemish out of the flock, or its equivalent, for a guilt offering, and the priest shall make atonement for him for the mistake that he made unintentionally, and he shall be forgiven.","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":18},{"ref":"Leviticus 5:19","short":"Lev 5:19","text":"It is a guilt offering; he has indeed incurred guilt before the LORD.”","url":"ot/leviticus/Leviticus_5.html","book":"Leviticus","ch":5,"v":19},{"ref":"Leviticus 6:1","short":"Lev 6:1","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":1},{"ref":"Leviticus 6:2","short":"Lev 6:2","text":"“If anyone sins and commits a breach of faith against the LORD by deceiving his neighbor in a matter of deposit or security, or through robbery, or if he has oppressed his neighbor","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":2},{"ref":"Leviticus 6:3","short":"Lev 6:3","text":"or has found something lost and lied about it, swearing falsely—in any of all the things that people do and sin thereby—","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":3},{"ref":"Leviticus 6:4","short":"Lev 6:4","text":"if he has sinned and has realized his guilt and will restore what he took by robbery or what he got by oppression or the deposit that was committed to him or the lost thing that he found","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":4},{"ref":"Leviticus 6:5","short":"Lev 6:5","text":"or anything about which he has sworn falsely, he shall restore it in full and shall add a fifth to it, and give it to him to whom it belongs on the day he realizes his guilt.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":5},{"ref":"Leviticus 6:6","short":"Lev 6:6","text":"And he shall bring to the priest as his compensation to the LORD a ram without blemish out of the flock, or its equivalent, for a guilt offering.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":6},{"ref":"Leviticus 6:7","short":"Lev 6:7","text":"And the priest shall make atonement for him before the LORD, and he shall be forgiven for any of the things that one may do and thereby become guilty.”","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":7},{"ref":"Leviticus 6:8","short":"Lev 6:8","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":8},{"ref":"Leviticus 6:9","short":"Lev 6:9","text":"“Command Aaron and his sons, saying, This is the law of the burnt offering. The burnt offering shall be on the hearth on the altar all night until the morning, and the fire of the altar shall be kept burning on it.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":9},{"ref":"Leviticus 6:10","short":"Lev 6:10","text":"And the priest shall put on his linen garment and put his linen undergarment on his body, and he shall take up the ashes to which the fire has reduced the burnt offering on the altar and put them beside the altar.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":10},{"ref":"Leviticus 6:11","short":"Lev 6:11","text":"Then he shall take off his garments and put on other garments and carry the ashes outside the camp to a clean place.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":11},{"ref":"Leviticus 6:12","short":"Lev 6:12","text":"The fire on the altar shall be kept burning on it; it shall not go out. The priest shall burn wood on it every morning, and he shall arrange the burnt offering on it and shall burn on it the fat of the peace offerings.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":12},{"ref":"Leviticus 6:13","short":"Lev 6:13","text":"Fire shall be kept burning on the altar continually; it shall not go out.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":13},{"ref":"Leviticus 6:14","short":"Lev 6:14","text":"“And this is the law of the grain offering. The sons of Aaron shall offer it before the LORD in front of the altar.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":14},{"ref":"Leviticus 6:15","short":"Lev 6:15","text":"And one shall take from it a handful of the fine flour of the grain offering and its oil and all the frankincense that is on the grain offering and burn this as its memorial portion on the altar, a pleasing aroma to the LORD.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":15},{"ref":"Leviticus 6:16","short":"Lev 6:16","text":"And the rest of it Aaron and his sons shall eat. It shall be eaten unleavened in a holy place. In the court of the tent of meeting they shall eat it.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":16},{"ref":"Leviticus 6:17","short":"Lev 6:17","text":"It shall not be baked with leaven. I have given it as their portion of my food offerings. It is a thing most holy, like the sin offering and the guilt offering.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":17},{"ref":"Leviticus 6:18","short":"Lev 6:18","text":"Every male among the children of Aaron may eat of it, as decreed forever throughout your generations, from the LORD’s food offerings. Whatever touches them shall become holy.”","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":18},{"ref":"Leviticus 6:19","short":"Lev 6:19","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":19},{"ref":"Leviticus 6:20","short":"Lev 6:20","text":"“This is the offering that Aaron and his sons shall offer to the LORD on the day when he is anointed: a tenth of an ephah of fine flour as a regular grain offering, half of it in the morning and half in the evening.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":20},{"ref":"Leviticus 6:21","short":"Lev 6:21","text":"It shall be made with oil on a griddle. You shall bring it well mixed, in baked pieces like a grain offering, and offer it for a pleasing aroma to the LORD.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":21},{"ref":"Leviticus 6:22","short":"Lev 6:22","text":"The priest from among Aaron’s sons, who is anointed to succeed him, shall offer it to the LORD as decreed forever. The whole of it shall be burned.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":22},{"ref":"Leviticus 6:23","short":"Lev 6:23","text":"Every grain offering of a priest shall be wholly burned. It shall not be eaten.”","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":23},{"ref":"Leviticus 6:24","short":"Lev 6:24","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":24},{"ref":"Leviticus 6:25","short":"Lev 6:25","text":"“Speak to Aaron and his sons, saying, This is the law of the sin offering. In the place where the burnt offering is killed shall the sin offering be killed before the LORD; it is most holy.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":25},{"ref":"Leviticus 6:26","short":"Lev 6:26","text":"The priest who offers it for sin shall eat it. In a holy place it shall be eaten, in the court of the tent of meeting.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":26},{"ref":"Leviticus 6:27","short":"Lev 6:27","text":"Whatever touches its flesh shall be holy, and when any of its blood is splashed on a garment, you shall wash that on which it was splashed in a holy place.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":27},{"ref":"Leviticus 6:28","short":"Lev 6:28","text":"And the earthenware vessel in which it is boiled shall be broken. But if it is boiled in a bronze vessel, that shall be scoured and rinsed in water.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":28},{"ref":"Leviticus 6:29","short":"Lev 6:29","text":"Every male among the priests may eat of it; it is most holy.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":29},{"ref":"Leviticus 6:30","short":"Lev 6:30","text":"But no sin offering shall be eaten from which any blood is brought into the tent of meeting to make atonement in the Holy Place; it shall be burned up with fire.","url":"ot/leviticus/Leviticus_6.html","book":"Leviticus","ch":6,"v":30},{"ref":"Leviticus 7:1","short":"Lev 7:1","text":"“This is the law of the guilt offering. It is most holy.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":1},{"ref":"Leviticus 7:2","short":"Lev 7:2","text":"In the place where they kill the burnt offering they shall kill the guilt offering, and its blood shall be thrown against the sides of the altar.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":2},{"ref":"Leviticus 7:3","short":"Lev 7:3","text":"And all its fat shall be offered, the fat tail, the fat that covers the entrails,","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":3},{"ref":"Leviticus 7:4","short":"Lev 7:4","text":"the two kidneys with the fat that is on them at the loins, and the long lobe of the liver that he shall remove with the kidneys.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":4},{"ref":"Leviticus 7:5","short":"Lev 7:5","text":"The priest shall burn them on the altar as a food offering to the LORD; it is a guilt offering.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":5},{"ref":"Leviticus 7:6","short":"Lev 7:6","text":"Every male among the priests may eat of it. It shall be eaten in a holy place. It is most holy.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":6},{"ref":"Leviticus 7:7","short":"Lev 7:7","text":"The guilt offering is just like the sin offering; there is one law for them. The priest who makes atonement with it shall have it.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":7},{"ref":"Leviticus 7:8","short":"Lev 7:8","text":"And the priest who offers any man’s burnt offering shall have for himself the skin of the burnt offering that he has offered.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":8},{"ref":"Leviticus 7:9","short":"Lev 7:9","text":"And every grain offering baked in the oven and all that is prepared on a pan or a griddle shall belong to the priest who offers it.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":9},{"ref":"Leviticus 7:10","short":"Lev 7:10","text":"And every grain offering, mixed with oil or dry, shall be shared equally among all the sons of Aaron.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":10},{"ref":"Leviticus 7:11","short":"Lev 7:11","text":"“And this is the law of the sacrifice of peace offerings that one may offer to the LORD.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":11},{"ref":"Leviticus 7:12","short":"Lev 7:12","text":"If he offers it for a thanksgiving, then he shall offer with the thanksgiving sacrifice unleavened loaves mixed with oil, unleavened wafers smeared with oil, and loaves of fine flour well mixed with oil.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":12},{"ref":"Leviticus 7:13","short":"Lev 7:13","text":"With the sacrifice of his peace offerings for thanksgiving he shall bring his offering with loaves of leavened bread.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":13},{"ref":"Leviticus 7:14","short":"Lev 7:14","text":"And from it he shall offer one loaf from each offering, as a gift to the LORD. It shall belong to the priest who throws the blood of the peace offerings.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":14},{"ref":"Leviticus 7:15","short":"Lev 7:15","text":"And the flesh of the sacrifice of his peace offerings for thanksgiving shall be eaten on the day of his offering. He shall not leave any of it until the morning.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":15},{"ref":"Leviticus 7:16","short":"Lev 7:16","text":"But if the sacrifice of his offering is a vow offering or a freewill offering, it shall be eaten on the day that he offers his sacrifice, and on the next day what remains of it shall be eaten.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":16},{"ref":"Leviticus 7:17","short":"Lev 7:17","text":"But what remains of the flesh of the sacrifice on the third day shall be burned up with fire.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":17},{"ref":"Leviticus 7:18","short":"Lev 7:18","text":"If any of the flesh of the sacrifice of his peace offering is eaten on the third day, he who offers it shall not be accepted, neither shall it be credited to him. It is tainted, and he who eats of it shall bear his iniquity.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":18},{"ref":"Leviticus 7:19","short":"Lev 7:19","text":"“Flesh that touches any unclean thing shall not be eaten. It shall be burned up with fire. All who are clean may eat flesh,","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":19},{"ref":"Leviticus 7:20","short":"Lev 7:20","text":"but the person who eats of the flesh of the sacrifice of the LORD’s peace offerings while an uncleanness is on him, that person shall be cut off from his people.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":20},{"ref":"Leviticus 7:21","short":"Lev 7:21","text":"And if anyone touches an unclean thing, whether human uncleanness or an unclean beast or any unclean detestable creature, and then eats some flesh from the sacrifice of the LORD’s peace offerings, that person shall be cut off from his people.”","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":21},{"ref":"Leviticus 7:22","short":"Lev 7:22","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":22},{"ref":"Leviticus 7:23","short":"Lev 7:23","text":"“Speak to the people of Israel, saying, You shall eat no fat, of ox or sheep or goat.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":23},{"ref":"Leviticus 7:24","short":"Lev 7:24","text":"The fat of an animal that dies of itself and the fat of one that is torn by beasts may be put to any other use, but on no account shall you eat it.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":24},{"ref":"Leviticus 7:25","short":"Lev 7:25","text":"For every person who eats of the fat of an animal of which a food offering may be made to the LORD shall be cut off from his people.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":25},{"ref":"Leviticus 7:26","short":"Lev 7:26","text":"Moreover, you shall eat no blood whatever, whether of fowl or of animal, in any of your dwelling places.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":26},{"ref":"Leviticus 7:27","short":"Lev 7:27","text":"Whoever eats any blood, that person shall be cut off from his people.”","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":27},{"ref":"Leviticus 7:28","short":"Lev 7:28","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":28},{"ref":"Leviticus 7:29","short":"Lev 7:29","text":"“Speak to the people of Israel, saying, Whoever offers the sacrifice of his peace offerings to the LORD shall bring his offering to the LORD from the sacrifice of his peace offerings.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":29},{"ref":"Leviticus 7:30","short":"Lev 7:30","text":"His own hands shall bring the LORD’s food offerings. He shall bring the fat with the breast, that the breast may be waved as a wave offering before the LORD.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":30},{"ref":"Leviticus 7:31","short":"Lev 7:31","text":"The priest shall burn the fat on the altar, but the breast shall be for Aaron and his sons.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":31},{"ref":"Leviticus 7:32","short":"Lev 7:32","text":"And the right thigh you shall give to the priest as a contribution from the sacrifice of your peace offerings.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":32},{"ref":"Leviticus 7:33","short":"Lev 7:33","text":"Whoever among the sons of Aaron offers the blood of the peace offerings and the fat shall have the right thigh for a portion.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":33},{"ref":"Leviticus 7:34","short":"Lev 7:34","text":"For the breast that is waved and the thigh that is contributed I have taken from the people of Israel, out of the sacrifices of their peace offerings, and have given them to Aaron the priest and to his sons, as a perpetual due from the people of Israel.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":34},{"ref":"Leviticus 7:35","short":"Lev 7:35","text":"This is the portion of Aaron and of his sons from the LORD’s food offerings, from the day they were presented to serve as priests of the LORD.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":35},{"ref":"Leviticus 7:36","short":"Lev 7:36","text":"The LORD commanded this to be given them by the people of Israel, from the day that he anointed them. It is a perpetual due throughout their generations.”","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":36},{"ref":"Leviticus 7:37","short":"Lev 7:37","text":"This is the law of the burnt offering, of the grain offering, of the sin offering, of the guilt offering, of the ordination offering, and of the peace offering,","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":37},{"ref":"Leviticus 7:38","short":"Lev 7:38","text":"which the LORD commanded Moses on Mount Sinai, on the day that he commanded the people of Israel to bring their offerings to the LORD, in the wilderness of Sinai.","url":"ot/leviticus/Leviticus_7.html","book":"Leviticus","ch":7,"v":38},{"ref":"Leviticus 8:1","short":"Lev 8:1","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":1},{"ref":"Leviticus 8:2","short":"Lev 8:2","text":"“Take Aaron and his sons with him, and the garments and the anointing oil and the bull of the sin offering and the two rams and the basket of unleavened bread.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":2},{"ref":"Leviticus 8:3","short":"Lev 8:3","text":"And assemble all the congregation at the entrance of the tent of meeting.”","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":3},{"ref":"Leviticus 8:4","short":"Lev 8:4","text":"And Moses did as the LORD commanded him, and the congregation was assembled at the entrance of the tent of meeting.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":4},{"ref":"Leviticus 8:5","short":"Lev 8:5","text":"And Moses said to the congregation, “This is the thing that the LORD has commanded to be done.”","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":5},{"ref":"Leviticus 8:6","short":"Lev 8:6","text":"And Moses brought Aaron and his sons and washed them with water.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":6},{"ref":"Leviticus 8:7","short":"Lev 8:7","text":"And he put the coat on him and tied the sash around his waist and clothed him with the robe and put the ephod on him and tied the skillfully woven band of the ephod around him, binding it to him with the band.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":7},{"ref":"Leviticus 8:8","short":"Lev 8:8","text":"And he placed the breastpiece on him, and in the breastpiece he put the Urim and the Thummim.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":8},{"ref":"Leviticus 8:9","short":"Lev 8:9","text":"And he set the turban on his head, and on the turban, in front, he set the golden plate, the holy crown, as the LORD commanded Moses.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":9},{"ref":"Leviticus 8:10","short":"Lev 8:10","text":"Then Moses took the anointing oil and anointed the tabernacle and all that was in it, and consecrated them.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":10},{"ref":"Leviticus 8:11","short":"Lev 8:11","text":"And he sprinkled some of it on the altar seven times, and anointed the altar and all its utensils and the basin and its stand, to consecrate them.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":11},{"ref":"Leviticus 8:12","short":"Lev 8:12","text":"And he poured some of the anointing oil on Aaron’s head and anointed him to consecrate him.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":12},{"ref":"Leviticus 8:13","short":"Lev 8:13","text":"And Moses brought Aaron’s sons and clothed them with coats and tied sashes around their waists and bound caps on them, as the LORD commanded Moses.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":13},{"ref":"Leviticus 8:14","short":"Lev 8:14","text":"Then he brought the bull of the sin offering, and Aaron and his sons laid their hands on the head of the bull of the sin offering.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":14},{"ref":"Leviticus 8:15","short":"Lev 8:15","text":"And he killed it, and Moses took the blood, and with his finger put it on the horns of the altar around it and purified the altar and poured out the blood at the base of the altar and consecrated it to make atonement for it.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":15},{"ref":"Leviticus 8:16","short":"Lev 8:16","text":"And he took all the fat that was on the entrails and the long lobe of the liver and the two kidneys with their fat, and Moses burned them on the altar.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":16},{"ref":"Leviticus 8:17","short":"Lev 8:17","text":"But the bull and its skin and its flesh and its dung he burned up with fire outside the camp, as the LORD commanded Moses.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":17},{"ref":"Leviticus 8:18","short":"Lev 8:18","text":"Then he presented the ram of the burnt offering, and Aaron and his sons laid their hands on the head of the ram.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":18},{"ref":"Leviticus 8:19","short":"Lev 8:19","text":"And he killed it, and Moses threw the blood against the sides of the altar.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":19},{"ref":"Leviticus 8:20","short":"Lev 8:20","text":"He cut the ram into pieces, and Moses burned the head and the pieces and the fat.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":20},{"ref":"Leviticus 8:21","short":"Lev 8:21","text":"He washed the entrails and the legs with water, and Moses burned the whole ram on the altar. It was a burnt offering with a pleasing aroma, a food offering for the LORD, as the LORD commanded Moses.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":21},{"ref":"Leviticus 8:22","short":"Lev 8:22","text":"Then he presented the other ram, the ram of ordination, and Aaron and his sons laid their hands on the head of the ram.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":22},{"ref":"Leviticus 8:23","short":"Lev 8:23","text":"And he killed it, and Moses took some of its blood and put it on the lobe of Aaron’s right ear and on the thumb of his right hand and on the big toe of his right foot.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":23},{"ref":"Leviticus 8:24","short":"Lev 8:24","text":"Then he presented Aaron’s sons, and Moses put some of the blood on the lobes of their right ears and on the thumbs of their right hands and on the big toes of their right feet. And Moses threw the blood against the sides of the altar.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":24},{"ref":"Leviticus 8:25","short":"Lev 8:25","text":"Then he took the fat and the fat tail and all the fat that was on the entrails and the long lobe of the liver and the two kidneys with their fat and the right thigh,","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":25},{"ref":"Leviticus 8:26","short":"Lev 8:26","text":"and out of the basket of unleavened bread that was before the LORD he took one unleavened loaf and one loaf of bread with oil and one wafer and placed them on the pieces of fat and on the right thigh.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":26},{"ref":"Leviticus 8:27","short":"Lev 8:27","text":"And he put all these in the hands of Aaron and in the hands of his sons and waved them as a wave offering before the LORD.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":27},{"ref":"Leviticus 8:28","short":"Lev 8:28","text":"Then Moses took them from their hands and burned them on the altar with the burnt offering. This was an ordination offering with a pleasing aroma, a food offering to the LORD.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":28},{"ref":"Leviticus 8:29","short":"Lev 8:29","text":"And Moses took the breast and waved it for a wave offering before the LORD. It was Moses’ portion of the ram of ordination, as the LORD commanded Moses.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":29},{"ref":"Leviticus 8:30","short":"Lev 8:30","text":"Then Moses took some of the anointing oil and of the blood that was on the altar and sprinkled it on Aaron and his garments, and also on his sons and his sons’ garments. So he consecrated Aaron and his garments, and his sons and his sons’ garments with him.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":30},{"ref":"Leviticus 8:31","short":"Lev 8:31","text":"And Moses said to Aaron and his sons, “Boil the flesh at the entrance of the tent of meeting, and there eat it and the bread that is in the basket of ordination offerings, as I commanded, saying, ‘Aaron and his sons shall eat it.’","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":31},{"ref":"Leviticus 8:32","short":"Lev 8:32","text":"And what remains of the flesh and the bread you shall burn up with fire.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":32},{"ref":"Leviticus 8:33","short":"Lev 8:33","text":"And you shall not go outside the entrance of the tent of meeting for seven days, until the days of your ordination are completed, for it will take seven days to ordain you.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":33},{"ref":"Leviticus 8:34","short":"Lev 8:34","text":"As has been done today, the LORD has commanded to be done to make atonement for you.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":34},{"ref":"Leviticus 8:35","short":"Lev 8:35","text":"At the entrance of the tent of meeting you shall remain day and night for seven days, performing what the LORD has charged, so that you do not die, for so I have been commanded.”","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":35},{"ref":"Leviticus 8:36","short":"Lev 8:36","text":"And Aaron and his sons did all the things that the LORD commanded by Moses.","url":"ot/leviticus/Leviticus_8.html","book":"Leviticus","ch":8,"v":36},{"ref":"Leviticus 9:1","short":"Lev 9:1","text":"On the eighth day Moses called Aaron and his sons and the elders of Israel,","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":1},{"ref":"Leviticus 9:2","short":"Lev 9:2","text":"and he said to Aaron, “Take for yourself a bull calf for a sin offering and a ram for a burnt offering, both without blemish, and offer them before the LORD.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":2},{"ref":"Leviticus 9:3","short":"Lev 9:3","text":"And say to the people of Israel, ‘Take a male goat for a sin offering, and a calf and a lamb, both a year old without blemish, for a burnt offering,","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":3},{"ref":"Leviticus 9:4","short":"Lev 9:4","text":"and an ox and a ram for peace offerings, to sacrifice before the LORD, and a grain offering mixed with oil, for today the LORD will appear to you.’”","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":4},{"ref":"Leviticus 9:5","short":"Lev 9:5","text":"And they brought what Moses commanded in front of the tent of meeting, and all the congregation drew near and stood before the LORD.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":5},{"ref":"Leviticus 9:6","short":"Lev 9:6","text":"And Moses said, “This is the thing that the LORD commanded you to do, that the glory of the LORD may appear to you.”","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":6},{"ref":"Leviticus 9:7","short":"Lev 9:7","text":"Then Moses said to Aaron, “Draw near to the altar and offer your sin offering and your burnt offering and make atonement for yourself and for the people, and bring the offering of the people and make atonement for them, as the LORD has commanded.”","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":7},{"ref":"Leviticus 9:8","short":"Lev 9:8","text":"So Aaron drew near to the altar and killed the calf of the sin offering, which was for himself.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":8},{"ref":"Leviticus 9:9","short":"Lev 9:9","text":"And the sons of Aaron presented the blood to him, and he dipped his finger in the blood and put it on the horns of the altar and poured out the blood at the base of the altar.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":9},{"ref":"Leviticus 9:10","short":"Lev 9:10","text":"But the fat and the kidneys and the long lobe of the liver from the sin offering he burned on the altar, as the LORD commanded Moses.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":10},{"ref":"Leviticus 9:11","short":"Lev 9:11","text":"The flesh and the skin he burned up with fire outside the camp.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":11},{"ref":"Leviticus 9:12","short":"Lev 9:12","text":"Then he killed the burnt offering, and Aaron’s sons handed him the blood, and he threw it against the sides of the altar.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":12},{"ref":"Leviticus 9:13","short":"Lev 9:13","text":"And they handed the burnt offering to him, piece by piece, and the head, and he burned them on the altar.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":13},{"ref":"Leviticus 9:14","short":"Lev 9:14","text":"And he washed the entrails and the legs and burned them with the burnt offering on the altar.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":14},{"ref":"Leviticus 9:15","short":"Lev 9:15","text":"Then he presented the people’s offering and took the goat of the sin offering that was for the people and killed it and offered it as a sin offering, like the first one.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":15},{"ref":"Leviticus 9:16","short":"Lev 9:16","text":"And he presented the burnt offering and offered it according to the rule.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":16},{"ref":"Leviticus 9:17","short":"Lev 9:17","text":"And he presented the grain offering, took a handful of it, and burned it on the altar, besides the burnt offering of the morning.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":17},{"ref":"Leviticus 9:18","short":"Lev 9:18","text":"Then he killed the ox and the ram, the sacrifice of peace offerings for the people. And Aaron’s sons handed him the blood, and he threw it against the sides of the altar.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":18},{"ref":"Leviticus 9:19","short":"Lev 9:19","text":"But the fat pieces of the ox and of the ram, the fat tail and that which covers the entrails and the kidneys and the long lobe of the liver—","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":19},{"ref":"Leviticus 9:20","short":"Lev 9:20","text":"they put the fat pieces on the breasts, and he burned the fat pieces on the altar,","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":20},{"ref":"Leviticus 9:21","short":"Lev 9:21","text":"but the breasts and the right thigh Aaron waved for a wave offering before the LORD, as Moses commanded.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":21},{"ref":"Leviticus 9:22","short":"Lev 9:22","text":"Then Aaron lifted up his hands toward the people and blessed them, and he came down from offering the sin offering and the burnt offering and the peace offerings.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":22},{"ref":"Leviticus 9:23","short":"Lev 9:23","text":"And Moses and Aaron went into the tent of meeting, and when they came out they blessed the people, and the glory of the LORD appeared to all the people.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":23},{"ref":"Leviticus 9:24","short":"Lev 9:24","text":"And fire came out from before the LORD and consumed the burnt offering and the pieces of fat on the altar, and when all the people saw it, they shouted and fell on their faces.","url":"ot/leviticus/Leviticus_9.html","book":"Leviticus","ch":9,"v":24},{"ref":"Leviticus 10:1","short":"Lev 10:1","text":"Now Nadab and Abihu, the sons of Aaron, each took his censer and put fire in it and laid incense on it and offered unauthorized fire before the LORD, which he had not commanded them.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":1},{"ref":"Leviticus 10:2","short":"Lev 10:2","text":"And fire came out from before the LORD and consumed them, and they died before the LORD.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":2},{"ref":"Leviticus 10:3","short":"Lev 10:3","text":"Then Moses said to Aaron, “This is what the LORD has said: ‘Among those who are near me I will be sanctified, and before all the people I will be glorified.’” And Aaron held his peace.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":3},{"ref":"Leviticus 10:4","short":"Lev 10:4","text":"And Moses called Mishael and Elzaphan, the sons of Uzziel the uncle of Aaron, and said to them, “Come near; carry your brothers away from the front of the sanctuary and out of the camp.”","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":4},{"ref":"Leviticus 10:5","short":"Lev 10:5","text":"So they came near and carried them in their coats out of the camp, as Moses had said.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":5},{"ref":"Leviticus 10:6","short":"Lev 10:6","text":"And Moses said to Aaron and to Eleazar and Ithamar his sons, “Do not let the hair of your heads hang loose, and do not tear your clothes, lest you die, and wrath come upon all the congregation; but let your brothers, the whole house of Israel, bewail the burning that the LORD has kindled.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":6},{"ref":"Leviticus 10:7","short":"Lev 10:7","text":"And do not go outside the entrance of the tent of meeting, lest you die, for the anointing oil of the LORD is upon you.” And they did according to the word of Moses.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":7},{"ref":"Leviticus 10:8","short":"Lev 10:8","text":"And the LORD spoke to Aaron, saying,","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":8},{"ref":"Leviticus 10:9","short":"Lev 10:9","text":"“Drink no wine or strong drink, you or your sons with you, when you go into the tent of meeting, lest you die. It shall be a statute forever throughout your generations.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":9},{"ref":"Leviticus 10:10","short":"Lev 10:10","text":"You are to distinguish between the holy and the common, and between the unclean and the clean,","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":10},{"ref":"Leviticus 10:11","short":"Lev 10:11","text":"and you are to teach the people of Israel all the statutes that the LORD has spoken to them by Moses.”","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":11},{"ref":"Leviticus 10:12","short":"Lev 10:12","text":"Moses spoke to Aaron and to Eleazar and Ithamar, his surviving sons: “Take the grain offering that is left of the LORD’s food offerings, and eat it unleavened beside the altar, for it is most holy.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":12},{"ref":"Leviticus 10:13","short":"Lev 10:13","text":"You shall eat it in a holy place, because it is your due and your sons’ due, from the LORD’s food offerings, for so I am commanded.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":13},{"ref":"Leviticus 10:14","short":"Lev 10:14","text":"But the breast that is waved and the thigh that is contributed you shall eat in a clean place, you and your sons and your daughters with you, for they are given as your due and your sons’ due from the sacrifices of the peace offerings of the people of Israel.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":14},{"ref":"Leviticus 10:15","short":"Lev 10:15","text":"The thigh that is contributed and the breast that is waved they shall bring with the food offerings of the fat pieces to wave for a wave offering before the LORD, and it shall be yours and your sons’ with you as a due forever, as the LORD has commanded.”","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":15},{"ref":"Leviticus 10:16","short":"Lev 10:16","text":"Now Moses diligently inquired about the goat of the sin offering, and behold, it was burned up! And he was angry with Eleazar and Ithamar, the surviving sons of Aaron, saying,","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":16},{"ref":"Leviticus 10:17","short":"Lev 10:17","text":"“Why have you not eaten the sin offering in the place of the sanctuary, since it is a thing most holy and has been given to you that you may bear the iniquity of the congregation, to make atonement for them before the LORD?","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":17},{"ref":"Leviticus 10:18","short":"Lev 10:18","text":"Behold, its blood was not brought into the inner part of the sanctuary. You certainly ought to have eaten it in the sanctuary, as I commanded.”","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":18},{"ref":"Leviticus 10:19","short":"Lev 10:19","text":"And Aaron said to Moses, “Behold, today they have offered their sin offering and their burnt offering before the LORD, and yet such things as these have happened to me! If I had eaten the sin offering today, would the LORD have approved?”","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":19},{"ref":"Leviticus 10:20","short":"Lev 10:20","text":"And when Moses heard that, he approved.","url":"ot/leviticus/Leviticus_10.html","book":"Leviticus","ch":10,"v":20},{"ref":"Leviticus 11:1","short":"Lev 11:1","text":"And the LORD spoke to Moses and Aaron, saying to them,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":1},{"ref":"Leviticus 11:2","short":"Lev 11:2","text":"“Speak to the people of Israel, saying, These are the living things that you may eat among all the animals that are on the earth.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":2},{"ref":"Leviticus 11:3","short":"Lev 11:3","text":"Whatever parts the hoof and is cloven-footed and chews the cud, among the animals, you may eat.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":3},{"ref":"Leviticus 11:4","short":"Lev 11:4","text":"Nevertheless, among those that chew the cud or part the hoof, you shall not eat these: The camel, because it chews the cud but does not part the hoof, is unclean to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":4},{"ref":"Leviticus 11:5","short":"Lev 11:5","text":"And the rock badger, because it chews the cud but does not part the hoof, is unclean to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":5},{"ref":"Leviticus 11:6","short":"Lev 11:6","text":"And the hare, because it chews the cud but does not part the hoof, is unclean to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":6},{"ref":"Leviticus 11:7","short":"Lev 11:7","text":"And the pig, because it parts the hoof and is cloven-footed but does not chew the cud, is unclean to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":7},{"ref":"Leviticus 11:8","short":"Lev 11:8","text":"You shall not eat any of their flesh, and you shall not touch their carcasses; they are unclean to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":8},{"ref":"Leviticus 11:9","short":"Lev 11:9","text":"“These you may eat, of all that are in the waters. Everything in the waters that has fins and scales, whether in the seas or in the rivers, you may eat.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":9},{"ref":"Leviticus 11:10","short":"Lev 11:10","text":"But anything in the seas or the rivers that does not have fins and scales, of the swarming creatures in the waters and of the living creatures that are in the waters, is detestable to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":10},{"ref":"Leviticus 11:11","short":"Lev 11:11","text":"You shall regard them as detestable; you shall not eat any of their flesh, and you shall detest their carcasses.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":11},{"ref":"Leviticus 11:12","short":"Lev 11:12","text":"Everything in the waters that does not have fins and scales is detestable to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":12},{"ref":"Leviticus 11:13","short":"Lev 11:13","text":"“And these you shall detest among the birds; they shall not be eaten; they are detestable: the eagle, the bearded vulture, the black vulture,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":13},{"ref":"Leviticus 11:14","short":"Lev 11:14","text":"the kite, the falcon of any kind,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":14},{"ref":"Leviticus 11:15","short":"Lev 11:15","text":"every raven of any kind,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":15},{"ref":"Leviticus 11:16","short":"Lev 11:16","text":"the ostrich, the nighthawk, the sea gull, the hawk of any kind,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":16},{"ref":"Leviticus 11:17","short":"Lev 11:17","text":"the little owl, the cormorant, the short-eared owl,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":17},{"ref":"Leviticus 11:18","short":"Lev 11:18","text":"the barn owl, the tawny owl, the carrion vulture,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":18},{"ref":"Leviticus 11:19","short":"Lev 11:19","text":"the stork, the heron of any kind, the hoopoe, and the bat.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":19},{"ref":"Leviticus 11:20","short":"Lev 11:20","text":"“All winged insects that go on all fours are detestable to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":20},{"ref":"Leviticus 11:21","short":"Lev 11:21","text":"Yet among the winged insects that go on all fours you may eat those that have jointed legs above their feet, with which to hop on the ground.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":21},{"ref":"Leviticus 11:22","short":"Lev 11:22","text":"Of them you may eat: the locust of any kind, the bald locust of any kind, the cricket of any kind, and the grasshopper of any kind.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":22},{"ref":"Leviticus 11:23","short":"Lev 11:23","text":"But all other winged insects that have four feet are detestable to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":23},{"ref":"Leviticus 11:24","short":"Lev 11:24","text":"“And by these you shall become unclean. Whoever touches their carcass shall be unclean until the evening,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":24},{"ref":"Leviticus 11:25","short":"Lev 11:25","text":"and whoever carries any part of their carcass shall wash his clothes and be unclean until the evening.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":25},{"ref":"Leviticus 11:26","short":"Lev 11:26","text":"Every animal that parts the hoof but is not cloven-footed or does not chew the cud is unclean to you. Everyone who touches them shall be unclean.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":26},{"ref":"Leviticus 11:27","short":"Lev 11:27","text":"And all that walk on their paws, among the animals that go on all fours, are unclean to you. Whoever touches their carcass shall be unclean until the evening,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":27},{"ref":"Leviticus 11:28","short":"Lev 11:28","text":"and he who carries their carcass shall wash his clothes and be unclean until the evening; they are unclean to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":28},{"ref":"Leviticus 11:29","short":"Lev 11:29","text":"“And these are unclean to you among the swarming things that swarm on the ground: the mole rat, the mouse, the great lizard of any kind,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":29},{"ref":"Leviticus 11:30","short":"Lev 11:30","text":"the gecko, the monitor lizard, the lizard, the sand lizard, and the chameleon.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":30},{"ref":"Leviticus 11:31","short":"Lev 11:31","text":"These are unclean to you among all that swarm. Whoever touches them when they are dead shall be unclean until the evening.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":31},{"ref":"Leviticus 11:32","short":"Lev 11:32","text":"And anything on which any of them falls when they are dead shall be unclean, whether it is an article of wood or a garment or a skin or a sack, any article that is used for any purpose. It must be put into water, and it shall be unclean until the evening; then it shall be clean.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":32},{"ref":"Leviticus 11:33","short":"Lev 11:33","text":"And if any of them falls into any earthenware vessel, all that is in it shall be unclean, and you shall break it.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":33},{"ref":"Leviticus 11:34","short":"Lev 11:34","text":"Any food in it that could be eaten, on which water comes, shall be unclean. And all drink that could be drunk from every such vessel shall be unclean.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":34},{"ref":"Leviticus 11:35","short":"Lev 11:35","text":"And everything on which any part of their carcass falls shall be unclean. Whether oven or stove, it shall be broken in pieces. They are unclean and shall remain unclean for you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":35},{"ref":"Leviticus 11:36","short":"Lev 11:36","text":"Nevertheless, a spring or a cistern holding water shall be clean, but whoever touches a carcass in them shall be unclean.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":36},{"ref":"Leviticus 11:37","short":"Lev 11:37","text":"And if any part of their carcass falls upon any seed grain that is to be sown, it is clean,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":37},{"ref":"Leviticus 11:38","short":"Lev 11:38","text":"but if water is put on the seed and any part of their carcass falls on it, it is unclean to you.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":38},{"ref":"Leviticus 11:39","short":"Lev 11:39","text":"“And if any animal which you may eat dies, whoever touches its carcass shall be unclean until the evening,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":39},{"ref":"Leviticus 11:40","short":"Lev 11:40","text":"and whoever eats of its carcass shall wash his clothes and be unclean until the evening. And whoever carries the carcass shall wash his clothes and be unclean until the evening.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":40},{"ref":"Leviticus 11:41","short":"Lev 11:41","text":"“Every swarming thing that swarms on the ground is detestable; it shall not be eaten.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":41},{"ref":"Leviticus 11:42","short":"Lev 11:42","text":"Whatever goes on its belly, and whatever goes on all fours, or whatever has many feet, any swarming thing that swarms on the ground, you shall not eat, for they are detestable.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":42},{"ref":"Leviticus 11:43","short":"Lev 11:43","text":"You shall not make yourselves detestable with any swarming thing that swarms, and you shall not defile yourselves with them, and become unclean through them.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":43},{"ref":"Leviticus 11:44","short":"Lev 11:44","text":"For I am the LORD your God. Consecrate yourselves therefore, and be holy, for I am holy. You shall not defile yourselves with any swarming thing that crawls on the ground.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":44},{"ref":"Leviticus 11:45","short":"Lev 11:45","text":"For I am the LORD who brought you up out of the land of Egypt to be your God. You shall therefore be holy, for I am holy.”","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":45},{"ref":"Leviticus 11:46","short":"Lev 11:46","text":"This is the law about beast and bird and every living creature that moves through the waters and every creature that swarms on the ground,","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":46},{"ref":"Leviticus 11:47","short":"Lev 11:47","text":"to make a distinction between the unclean and the clean and between the living creature that may be eaten and the living creature that may not be eaten.","url":"ot/leviticus/Leviticus_11.html","book":"Leviticus","ch":11,"v":47},{"ref":"Leviticus 12:1","short":"Lev 12:1","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_12.html","book":"Leviticus","ch":12,"v":1},{"ref":"Leviticus 12:2","short":"Lev 12:2","text":"“Speak to the people of Israel, saying, If a woman conceives and bears a male child, then she shall be unclean seven days. As at the time of her menstruation, she shall be unclean.","url":"ot/leviticus/Leviticus_12.html","book":"Leviticus","ch":12,"v":2},{"ref":"Leviticus 12:3","short":"Lev 12:3","text":"And on the eighth day the flesh of his foreskin shall be circumcised.","url":"ot/leviticus/Leviticus_12.html","book":"Leviticus","ch":12,"v":3},{"ref":"Leviticus 12:4","short":"Lev 12:4","text":"Then she shall continue for thirty-three days in the blood of her purifying. She shall not touch anything holy, nor come into the sanctuary, until the days of her purifying are completed.","url":"ot/leviticus/Leviticus_12.html","book":"Leviticus","ch":12,"v":4},{"ref":"Leviticus 12:5","short":"Lev 12:5","text":"But if she bears a female child, then she shall be unclean two weeks, as in her menstruation. And she shall continue in the blood of her purifying for sixty-six days.","url":"ot/leviticus/Leviticus_12.html","book":"Leviticus","ch":12,"v":5},{"ref":"Leviticus 12:6","short":"Lev 12:6","text":"“And when the days of her purifying are completed, whether for a son or for a daughter, she shall bring to the priest at the entrance of the tent of meeting a lamb a year old for a burnt offering, and a pigeon or a turtledove for a sin offering,","url":"ot/leviticus/Leviticus_12.html","book":"Leviticus","ch":12,"v":6},{"ref":"Leviticus 12:7","short":"Lev 12:7","text":"and he shall offer it before the LORD and make atonement for her. Then she shall be clean from the flow of her blood. This is the law for her who bears a child, either male or female.","url":"ot/leviticus/Leviticus_12.html","book":"Leviticus","ch":12,"v":7},{"ref":"Leviticus 12:8","short":"Lev 12:8","text":"And if she cannot afford a lamb, then she shall take two turtledoves or two pigeons, one for a burnt offering and the other for a sin offering. And the priest shall make atonement for her, and she shall be clean.”","url":"ot/leviticus/Leviticus_12.html","book":"Leviticus","ch":12,"v":8},{"ref":"Leviticus 13:1","short":"Lev 13:1","text":"The LORD spoke to Moses and Aaron, saying,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":1},{"ref":"Leviticus 13:2","short":"Lev 13:2","text":"“When a person has on the skin of his body a swelling or an eruption or a spot, and it turns into a case of leprous disease on the skin of his body, then he shall be brought to Aaron the priest or to one of his sons the priests,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":2},{"ref":"Leviticus 13:3","short":"Lev 13:3","text":"and the priest shall examine the diseased area on the skin of his body. And if the hair in the diseased area has turned white and the disease appears to be deeper than the skin of his body, it is a case of leprous disease. When the priest has examined him, he shall pronounce him unclean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":3},{"ref":"Leviticus 13:4","short":"Lev 13:4","text":"But if the spot is white in the skin of his body and appears no deeper than the skin, and the hair in it has not turned white, the priest shall shut up the diseased person for seven days.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":4},{"ref":"Leviticus 13:5","short":"Lev 13:5","text":"And the priest shall examine him on the seventh day, and if in his eyes the disease is checked and the disease has not spread in the skin, then the priest shall shut him up for another seven days.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":5},{"ref":"Leviticus 13:6","short":"Lev 13:6","text":"And the priest shall examine him again on the seventh day, and if the diseased area has faded and the disease has not spread in the skin, then the priest shall pronounce him clean; it is only an eruption. And he shall wash his clothes and be clean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":6},{"ref":"Leviticus 13:7","short":"Lev 13:7","text":"But if the eruption spreads in the skin, after he has shown himself to the priest for his cleansing, he shall appear again before the priest.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":7},{"ref":"Leviticus 13:8","short":"Lev 13:8","text":"And the priest shall look, and if the eruption has spread in the skin, then the priest shall pronounce him unclean; it is a leprous disease.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":8},{"ref":"Leviticus 13:9","short":"Lev 13:9","text":"“When a man is afflicted with a leprous disease, he shall be brought to the priest,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":9},{"ref":"Leviticus 13:10","short":"Lev 13:10","text":"and the priest shall look. And if there is a white swelling in the skin that has turned the hair white, and there is raw flesh in the swelling,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":10},{"ref":"Leviticus 13:11","short":"Lev 13:11","text":"it is a chronic leprous disease in the skin of his body, and the priest shall pronounce him unclean. He shall not shut him up, for he is unclean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":11},{"ref":"Leviticus 13:12","short":"Lev 13:12","text":"And if the leprous disease breaks out in the skin, so that the leprous disease covers all the skin of the diseased person from head to foot, so far as the priest can see,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":12},{"ref":"Leviticus 13:13","short":"Lev 13:13","text":"then the priest shall look, and if the leprous disease has covered all his body, he shall pronounce him clean of the disease; it has all turned white, and he is clean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":13},{"ref":"Leviticus 13:14","short":"Lev 13:14","text":"But when raw flesh appears on him, he shall be unclean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":14},{"ref":"Leviticus 13:15","short":"Lev 13:15","text":"And the priest shall examine the raw flesh and pronounce him unclean. Raw flesh is unclean, for it is a leprous disease.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":15},{"ref":"Leviticus 13:16","short":"Lev 13:16","text":"But if the raw flesh recovers and turns white again, then he shall come to the priest,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":16},{"ref":"Leviticus 13:17","short":"Lev 13:17","text":"and the priest shall examine him, and if the disease has turned white, then the priest shall pronounce the diseased person clean; he is clean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":17},{"ref":"Leviticus 13:18","short":"Lev 13:18","text":"“If there is in the skin of one’s body a boil and it heals,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":18},{"ref":"Leviticus 13:19","short":"Lev 13:19","text":"and in the place of the boil there comes a white swelling or a reddish-white spot, then it shall be shown to the priest.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":19},{"ref":"Leviticus 13:20","short":"Lev 13:20","text":"And the priest shall look, and if it appears deeper than the skin and its hair has turned white, then the priest shall pronounce him unclean. It is a case of leprous disease that has broken out in the boil.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":20},{"ref":"Leviticus 13:21","short":"Lev 13:21","text":"But if the priest examines it and there is no white hair in it and it is not deeper than the skin, but has faded, then the priest shall shut him up seven days.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":21},{"ref":"Leviticus 13:22","short":"Lev 13:22","text":"And if it spreads in the skin, then the priest shall pronounce him unclean; it is a disease.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":22},{"ref":"Leviticus 13:23","short":"Lev 13:23","text":"But if the spot remains in one place and does not spread, it is the scar of the boil, and the priest shall pronounce him clean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":23},{"ref":"Leviticus 13:24","short":"Lev 13:24","text":"“Or, when the body has a burn on its skin and the raw flesh of the burn becomes a spot, reddish-white or white,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":24},{"ref":"Leviticus 13:25","short":"Lev 13:25","text":"the priest shall examine it, and if the hair in the spot has turned white and it appears deeper than the skin, then it is a leprous disease. It has broken out in the burn, and the priest shall pronounce him unclean; it is a case of leprous disease.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":25},{"ref":"Leviticus 13:26","short":"Lev 13:26","text":"But if the priest examines it and there is no white hair in the spot and it is no deeper than the skin, but has faded, the priest shall shut him up seven days,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":26},{"ref":"Leviticus 13:27","short":"Lev 13:27","text":"and the priest shall examine him the seventh day. If it is spreading in the skin, then the priest shall pronounce him unclean; it is a case of leprous disease.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":27},{"ref":"Leviticus 13:28","short":"Lev 13:28","text":"But if the spot remains in one place and does not spread in the skin, but has faded, it is a swelling from the burn, and the priest shall pronounce him clean, for it is the scar of the burn.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":28},{"ref":"Leviticus 13:29","short":"Lev 13:29","text":"“When a man or woman has a disease on the head or the beard,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":29},{"ref":"Leviticus 13:30","short":"Lev 13:30","text":"the priest shall examine the disease. And if it appears deeper than the skin, and the hair in it is yellow and thin, then the priest shall pronounce him unclean. It is an itch, a leprous disease of the head or the beard.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":30},{"ref":"Leviticus 13:31","short":"Lev 13:31","text":"And if the priest examines the itching disease and it appears no deeper than the skin and there is no black hair in it, then the priest shall shut up the person with the itching disease for seven days,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":31},{"ref":"Leviticus 13:32","short":"Lev 13:32","text":"and on the seventh day the priest shall examine the disease. If the itch has not spread, and there is in it no yellow hair, and the itch appears to be no deeper than the skin,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":32},{"ref":"Leviticus 13:33","short":"Lev 13:33","text":"then he shall shave himself, but the itch he shall not shave; and the priest shall shut up the person with the itching disease for another seven days.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":33},{"ref":"Leviticus 13:34","short":"Lev 13:34","text":"And on the seventh day the priest shall examine the itch, and if the itch has not spread in the skin and it appears to be no deeper than the skin, then the priest shall pronounce him clean. And he shall wash his clothes and be clean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":34},{"ref":"Leviticus 13:35","short":"Lev 13:35","text":"But if the itch spreads in the skin after his cleansing,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":35},{"ref":"Leviticus 13:36","short":"Lev 13:36","text":"then the priest shall examine him, and if the itch has spread in the skin, the priest need not seek for the yellow hair; he is unclean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":36},{"ref":"Leviticus 13:37","short":"Lev 13:37","text":"But if in his eyes the itch is unchanged and black hair has grown in it, the itch is healed and he is clean, and the priest shall pronounce him clean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":37},{"ref":"Leviticus 13:38","short":"Lev 13:38","text":"“When a man or a woman has spots on the skin of the body, white spots,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":38},{"ref":"Leviticus 13:39","short":"Lev 13:39","text":"the priest shall look, and if the spots on the skin of the body are of a dull white, it is leukoderma that has broken out in the skin; he is clean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":39},{"ref":"Leviticus 13:40","short":"Lev 13:40","text":"“If a man’s hair falls out from his head, he is bald; he is clean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":40},{"ref":"Leviticus 13:41","short":"Lev 13:41","text":"And if a man’s hair falls out from his forehead, he has baldness of the forehead; he is clean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":41},{"ref":"Leviticus 13:42","short":"Lev 13:42","text":"But if there is on the bald head or the bald forehead a reddish-white diseased area, it is a leprous disease breaking out on his bald head or his bald forehead.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":42},{"ref":"Leviticus 13:43","short":"Lev 13:43","text":"Then the priest shall examine him, and if the diseased swelling is reddish-white on his bald head or on his bald forehead, like the appearance of leprous disease in the skin of the body,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":43},{"ref":"Leviticus 13:44","short":"Lev 13:44","text":"he is a leprous man, he is unclean. The priest must pronounce him unclean; his disease is on his head.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":44},{"ref":"Leviticus 13:45","short":"Lev 13:45","text":"“The leprous person who has the disease shall wear torn clothes and let the hair of his head hang loose, and he shall cover his upper lip and cry out, ‘Unclean, unclean.’","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":45},{"ref":"Leviticus 13:46","short":"Lev 13:46","text":"He shall remain unclean as long as he has the disease. He is unclean. He shall live alone. His dwelling shall be outside the camp.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":46},{"ref":"Leviticus 13:47","short":"Lev 13:47","text":"“When there is a case of leprous disease in a garment, whether a woolen or a linen garment,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":47},{"ref":"Leviticus 13:48","short":"Lev 13:48","text":"in warp or woof of linen or wool, or in a skin or in anything made of skin,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":48},{"ref":"Leviticus 13:49","short":"Lev 13:49","text":"if the disease is greenish or reddish in the garment, or in the skin or in the warp or the woof or in any article made of skin, it is a case of leprous disease, and it shall be shown to the priest.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":49},{"ref":"Leviticus 13:50","short":"Lev 13:50","text":"And the priest shall examine the disease and shut up that which has the disease for seven days.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":50},{"ref":"Leviticus 13:51","short":"Lev 13:51","text":"Then he shall examine the disease on the seventh day. If the disease has spread in the garment, in the warp or the woof, or in the skin, whatever be the use of the skin, the disease is a persistent leprous disease; it is unclean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":51},{"ref":"Leviticus 13:52","short":"Lev 13:52","text":"And he shall burn the garment, or the warp or the woof, the wool or the linen, or any article made of skin that is diseased, for it is a persistent leprous disease. It shall be burned in the fire.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":52},{"ref":"Leviticus 13:53","short":"Lev 13:53","text":"“And if the priest examines, and if the disease has not spread in the garment, in the warp or the woof or in any article made of skin,","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":53},{"ref":"Leviticus 13:54","short":"Lev 13:54","text":"then the priest shall command that they wash the thing in which is the disease, and he shall shut it up for another seven days.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":54},{"ref":"Leviticus 13:55","short":"Lev 13:55","text":"And the priest shall examine the diseased thing after it has been washed. And if the appearance of the diseased area has not changed, though the disease has not spread, it is unclean. You shall burn it in the fire, whether the rot is on the back or on the front.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":55},{"ref":"Leviticus 13:56","short":"Lev 13:56","text":"“But if the priest examines, and if the diseased area has faded after it has been washed, he shall tear it out of the garment or the skin or the warp or the woof.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":56},{"ref":"Leviticus 13:57","short":"Lev 13:57","text":"Then if it appears again in the garment, in the warp or the woof, or in any article made of skin, it is spreading. You shall burn with fire whatever has the disease.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":57},{"ref":"Leviticus 13:58","short":"Lev 13:58","text":"But the garment, or the warp or the woof, or any article made of skin from which the disease departs when you have washed it, shall then be washed a second time, and be clean.”","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":58},{"ref":"Leviticus 13:59","short":"Lev 13:59","text":"This is the law for a case of leprous disease in a garment of wool or linen, either in the warp or the woof, or in any article made of skin, to determine whether it is clean or unclean.","url":"ot/leviticus/Leviticus_13.html","book":"Leviticus","ch":13,"v":59},{"ref":"Leviticus 14:1","short":"Lev 14:1","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":1},{"ref":"Leviticus 14:2","short":"Lev 14:2","text":"“This shall be the law of the leprous person for the day of his cleansing. He shall be brought to the priest,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":2},{"ref":"Leviticus 14:3","short":"Lev 14:3","text":"and the priest shall go out of the camp, and the priest shall look. Then, if the case of leprous disease is healed in the leprous person,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":3},{"ref":"Leviticus 14:4","short":"Lev 14:4","text":"the priest shall command them to take for him who is to be cleansed two live clean birds and cedarwood and scarlet yarn and hyssop.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":4},{"ref":"Leviticus 14:5","short":"Lev 14:5","text":"And the priest shall command them to kill one of the birds in an earthenware vessel over fresh water.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":5},{"ref":"Leviticus 14:6","short":"Lev 14:6","text":"He shall take the live bird with the cedarwood and the scarlet yarn and the hyssop, and dip them and the live bird in the blood of the bird that was killed over the fresh water.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":6},{"ref":"Leviticus 14:7","short":"Lev 14:7","text":"And he shall sprinkle it seven times on him who is to be cleansed of the leprous disease. Then he shall pronounce him clean and shall let the living bird go into the open field.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":7},{"ref":"Leviticus 14:8","short":"Lev 14:8","text":"And he who is to be cleansed shall wash his clothes and shave off all his hair and bathe himself in water, and he shall be clean. And after that he may come into the camp, but live outside his tent seven days.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":8},{"ref":"Leviticus 14:9","short":"Lev 14:9","text":"And on the seventh day he shall shave off all his hair from his head, his beard, and his eyebrows. He shall shave off all his hair, and then he shall wash his clothes and bathe his body in water, and he shall be clean.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":9},{"ref":"Leviticus 14:10","short":"Lev 14:10","text":"“And on the eighth day he shall take two male lambs without blemish, and one ewe lamb a year old without blemish, and a grain offering of three tenths of an ephah of fine flour mixed with oil, and one log of oil.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":10},{"ref":"Leviticus 14:11","short":"Lev 14:11","text":"And the priest who cleanses him shall set the man who is to be cleansed and these things before the LORD, at the entrance of the tent of meeting.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":11},{"ref":"Leviticus 14:12","short":"Lev 14:12","text":"And the priest shall take one of the male lambs and offer it for a guilt offering, along with the log of oil, and wave them for a wave offering before the LORD.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":12},{"ref":"Leviticus 14:13","short":"Lev 14:13","text":"And he shall kill the lamb in the place where they kill the sin offering and the burnt offering, in the place of the sanctuary. For the guilt offering, like the sin offering, belongs to the priest; it is most holy.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":13},{"ref":"Leviticus 14:14","short":"Lev 14:14","text":"The priest shall take some of the blood of the guilt offering, and the priest shall put it on the lobe of the right ear of him who is to be cleansed and on the thumb of his right hand and on the big toe of his right foot.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":14},{"ref":"Leviticus 14:15","short":"Lev 14:15","text":"Then the priest shall take some of the log of oil and pour it into the palm of his own left hand","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":15},{"ref":"Leviticus 14:16","short":"Lev 14:16","text":"and dip his right finger in the oil that is in his left hand and sprinkle some oil with his finger seven times before the LORD.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":16},{"ref":"Leviticus 14:17","short":"Lev 14:17","text":"And some of the oil that remains in his hand the priest shall put on the lobe of the right ear of him who is to be cleansed and on the thumb of his right hand and on the big toe of his right foot, on top of the blood of the guilt offering.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":17},{"ref":"Leviticus 14:18","short":"Lev 14:18","text":"And the rest of the oil that is in the priest’s hand he shall put on the head of him who is to be cleansed. Then the priest shall make atonement for him before the LORD.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":18},{"ref":"Leviticus 14:19","short":"Lev 14:19","text":"The priest shall offer the sin offering, to make atonement for him who is to be cleansed from his uncleanness. And afterward he shall kill the burnt offering.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":19},{"ref":"Leviticus 14:20","short":"Lev 14:20","text":"And the priest shall offer the burnt offering and the grain offering on the altar. Thus the priest shall make atonement for him, and he shall be clean.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":20},{"ref":"Leviticus 14:21","short":"Lev 14:21","text":"“But if he is poor and cannot afford so much, then he shall take one male lamb for a guilt offering to be waved, to make atonement for him, and a tenth of an ephah of fine flour mixed with oil for a grain offering, and a log of oil;","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":21},{"ref":"Leviticus 14:22","short":"Lev 14:22","text":"also two turtledoves or two pigeons, whichever he can afford. The one shall be a sin offering and the other a burnt offering.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":22},{"ref":"Leviticus 14:23","short":"Lev 14:23","text":"And on the eighth day he shall bring them for his cleansing to the priest, to the entrance of the tent of meeting, before the LORD.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":23},{"ref":"Leviticus 14:24","short":"Lev 14:24","text":"And the priest shall take the lamb of the guilt offering and the log of oil, and the priest shall wave them for a wave offering before the LORD.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":24},{"ref":"Leviticus 14:25","short":"Lev 14:25","text":"And he shall kill the lamb of the guilt offering. And the priest shall take some of the blood of the guilt offering and put it on the lobe of the right ear of him who is to be cleansed, and on the thumb of his right hand and on the big toe of his right foot.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":25},{"ref":"Leviticus 14:26","short":"Lev 14:26","text":"And the priest shall pour some of the oil into the palm of his own left hand,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":26},{"ref":"Leviticus 14:27","short":"Lev 14:27","text":"and shall sprinkle with his right finger some of the oil that is in his left hand seven times before the LORD.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":27},{"ref":"Leviticus 14:28","short":"Lev 14:28","text":"And the priest shall put some of the oil that is in his hand on the lobe of the right ear of him who is to be cleansed and on the thumb of his right hand and on the big toe of his right foot, in the place where the blood of the guilt offering was put.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":28},{"ref":"Leviticus 14:29","short":"Lev 14:29","text":"And the rest of the oil that is in the priest’s hand he shall put on the head of him who is to be cleansed, to make atonement for him before the LORD.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":29},{"ref":"Leviticus 14:30","short":"Lev 14:30","text":"And he shall offer, of the turtledoves or pigeons, whichever he can afford,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":30},{"ref":"Leviticus 14:31","short":"Lev 14:31","text":"one for a sin offering and the other for a burnt offering, along with a grain offering. And the priest shall make atonement before the LORD for him who is being cleansed.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":31},{"ref":"Leviticus 14:32","short":"Lev 14:32","text":"This is the law for him in whom is a case of leprous disease, who cannot afford the offerings for his cleansing.”","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":32},{"ref":"Leviticus 14:33","short":"Lev 14:33","text":"The LORD spoke to Moses and Aaron, saying,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":33},{"ref":"Leviticus 14:34","short":"Lev 14:34","text":"“When you come into the land of Canaan, which I give you for a possession, and I put a case of leprous disease in a house in the land of your possession,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":34},{"ref":"Leviticus 14:35","short":"Lev 14:35","text":"then he who owns the house shall come and tell the priest, ‘There seems to me to be some case of disease in my house.’","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":35},{"ref":"Leviticus 14:36","short":"Lev 14:36","text":"Then the priest shall command that they empty the house before the priest goes to examine the disease, lest all that is in the house be declared unclean. And afterward the priest shall go in to see the house.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":36},{"ref":"Leviticus 14:37","short":"Lev 14:37","text":"And he shall examine the disease. And if the disease is in the walls of the house with greenish or reddish spots, and if it appears to be deeper than the surface,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":37},{"ref":"Leviticus 14:38","short":"Lev 14:38","text":"then the priest shall go out of the house to the door of the house and shut up the house seven days.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":38},{"ref":"Leviticus 14:39","short":"Lev 14:39","text":"And the priest shall come again on the seventh day, and look. If the disease has spread in the walls of the house,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":39},{"ref":"Leviticus 14:40","short":"Lev 14:40","text":"then the priest shall command that they take out the stones in which is the disease and throw them into an unclean place outside the city.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":40},{"ref":"Leviticus 14:41","short":"Lev 14:41","text":"And he shall have the inside of the house scraped all around, and the plaster that they scrape off they shall pour out in an unclean place outside the city.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":41},{"ref":"Leviticus 14:42","short":"Lev 14:42","text":"Then they shall take other stones and put them in the place of those stones, and he shall take other plaster and plaster the house.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":42},{"ref":"Leviticus 14:43","short":"Lev 14:43","text":"“If the disease breaks out again in the house, after he has taken out the stones and scraped the house and plastered it,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":43},{"ref":"Leviticus 14:44","short":"Lev 14:44","text":"then the priest shall go and look. And if the disease has spread in the house, it is a persistent leprous disease in the house; it is unclean.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":44},{"ref":"Leviticus 14:45","short":"Lev 14:45","text":"And he shall break down the house, its stones and timber and all the plaster of the house, and he shall carry them out of the city to an unclean place.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":45},{"ref":"Leviticus 14:46","short":"Lev 14:46","text":"Moreover, whoever enters the house while it is shut up shall be unclean until the evening,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":46},{"ref":"Leviticus 14:47","short":"Lev 14:47","text":"and whoever sleeps in the house shall wash his clothes, and whoever eats in the house shall wash his clothes.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":47},{"ref":"Leviticus 14:48","short":"Lev 14:48","text":"“But if the priest comes and looks, and if the disease has not spread in the house after the house was plastered, then the priest shall pronounce the house clean, for the disease is healed.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":48},{"ref":"Leviticus 14:49","short":"Lev 14:49","text":"And for the cleansing of the house he shall take two small birds, with cedarwood and scarlet yarn and hyssop,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":49},{"ref":"Leviticus 14:50","short":"Lev 14:50","text":"and shall kill one of the birds in an earthenware vessel over fresh water","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":50},{"ref":"Leviticus 14:51","short":"Lev 14:51","text":"and shall take the cedarwood and the hyssop and the scarlet yarn, along with the live bird, and dip them in the blood of the bird that was killed and in the fresh water and sprinkle the house seven times.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":51},{"ref":"Leviticus 14:52","short":"Lev 14:52","text":"Thus he shall cleanse the house with the blood of the bird and with the fresh water and with the live bird and with the cedarwood and hyssop and scarlet yarn.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":52},{"ref":"Leviticus 14:53","short":"Lev 14:53","text":"And he shall let the live bird go out of the city into the open country. So he shall make atonement for the house, and it shall be clean.”","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":53},{"ref":"Leviticus 14:54","short":"Lev 14:54","text":"This is the law for any case of leprous disease: for an itch,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":54},{"ref":"Leviticus 14:55","short":"Lev 14:55","text":"for leprous disease in a garment or in a house,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":55},{"ref":"Leviticus 14:56","short":"Lev 14:56","text":"and for a swelling or an eruption or a spot,","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":56},{"ref":"Leviticus 14:57","short":"Lev 14:57","text":"to show when it is unclean and when it is clean. This is the law for leprous disease.","url":"ot/leviticus/Leviticus_14.html","book":"Leviticus","ch":14,"v":57},{"ref":"Leviticus 15:1","short":"Lev 15:1","text":"The LORD spoke to Moses and Aaron, saying,","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":1},{"ref":"Leviticus 15:2","short":"Lev 15:2","text":"“Speak to the people of Israel and say to them, When any man has a discharge from his body, his discharge is unclean.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":2},{"ref":"Leviticus 15:3","short":"Lev 15:3","text":"And this is the law of his uncleanness for a discharge: whether his body runs with his discharge, or his body is blocked up by his discharge, it is his uncleanness.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":3},{"ref":"Leviticus 15:4","short":"Lev 15:4","text":"Every bed on which the one with the discharge lies shall be unclean, and everything on which he sits shall be unclean.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":4},{"ref":"Leviticus 15:5","short":"Lev 15:5","text":"And anyone who touches his bed shall wash his clothes and bathe himself in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":5},{"ref":"Leviticus 15:6","short":"Lev 15:6","text":"And whoever sits on anything on which the one with the discharge has sat shall wash his clothes and bathe himself in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":6},{"ref":"Leviticus 15:7","short":"Lev 15:7","text":"And whoever touches the body of the one with the discharge shall wash his clothes and bathe himself in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":7},{"ref":"Leviticus 15:8","short":"Lev 15:8","text":"And if the one with the discharge spits on someone who is clean, then he shall wash his clothes and bathe himself in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":8},{"ref":"Leviticus 15:9","short":"Lev 15:9","text":"And any saddle on which the one with the discharge rides shall be unclean.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":9},{"ref":"Leviticus 15:10","short":"Lev 15:10","text":"And whoever touches anything that was under him shall be unclean until the evening. And whoever carries such things shall wash his clothes and bathe himself in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":10},{"ref":"Leviticus 15:11","short":"Lev 15:11","text":"Anyone whom the one with the discharge touches without having rinsed his hands in water shall wash his clothes and bathe himself in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":11},{"ref":"Leviticus 15:12","short":"Lev 15:12","text":"And an earthenware vessel that the one with the discharge touches shall be broken, and every vessel of wood shall be rinsed in water.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":12},{"ref":"Leviticus 15:13","short":"Lev 15:13","text":"“And when the one with a discharge is cleansed of his discharge, then he shall count for himself seven days for his cleansing, and wash his clothes. And he shall bathe his body in fresh water and shall be clean.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":13},{"ref":"Leviticus 15:14","short":"Lev 15:14","text":"And on the eighth day he shall take two turtledoves or two pigeons and come before the LORD to the entrance of the tent of meeting and give them to the priest.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":14},{"ref":"Leviticus 15:15","short":"Lev 15:15","text":"And the priest shall use them, one for a sin offering and the other for a burnt offering. And the priest shall make atonement for him before the LORD for his discharge.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":15},{"ref":"Leviticus 15:16","short":"Lev 15:16","text":"“If a man has an emission of semen, he shall bathe his whole body in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":16},{"ref":"Leviticus 15:17","short":"Lev 15:17","text":"And every garment and every skin on which the semen comes shall be washed with water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":17},{"ref":"Leviticus 15:18","short":"Lev 15:18","text":"If a man lies with a woman and has an emission of semen, both of them shall bathe themselves in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":18},{"ref":"Leviticus 15:19","short":"Lev 15:19","text":"“When a woman has a discharge, and the discharge in her body is blood, she shall be in her menstrual impurity for seven days, and whoever touches her shall be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":19},{"ref":"Leviticus 15:20","short":"Lev 15:20","text":"And everything on which she lies during her menstrual impurity shall be unclean. Everything also on which she sits shall be unclean.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":20},{"ref":"Leviticus 15:21","short":"Lev 15:21","text":"And whoever touches her bed shall wash his clothes and bathe himself in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":21},{"ref":"Leviticus 15:22","short":"Lev 15:22","text":"And whoever touches anything on which she sits shall wash his clothes and bathe himself in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":22},{"ref":"Leviticus 15:23","short":"Lev 15:23","text":"Whether it is the bed or anything on which she sits, when he touches it he shall be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":23},{"ref":"Leviticus 15:24","short":"Lev 15:24","text":"And if any man lies with her and her menstrual impurity comes upon him, he shall be unclean seven days, and every bed on which he lies shall be unclean.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":24},{"ref":"Leviticus 15:25","short":"Lev 15:25","text":"“If a woman has a discharge of blood for many days, not at the time of her menstrual impurity, or if she has a discharge beyond the time of her impurity, all the days of the discharge she shall continue in uncleanness. As in the days of her impurity, she shall be unclean.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":25},{"ref":"Leviticus 15:26","short":"Lev 15:26","text":"Every bed on which she lies, all the days of her discharge, shall be to her as the bed of her impurity. And everything on which she sits shall be unclean, as in the uncleanness of her menstrual impurity.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":26},{"ref":"Leviticus 15:27","short":"Lev 15:27","text":"And whoever touches these things shall be unclean, and shall wash his clothes and bathe himself in water and be unclean until the evening.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":27},{"ref":"Leviticus 15:28","short":"Lev 15:28","text":"But if she is cleansed of her discharge, she shall count for herself seven days, and after that she shall be clean.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":28},{"ref":"Leviticus 15:29","short":"Lev 15:29","text":"And on the eighth day she shall take two turtledoves or two pigeons and bring them to the priest, to the entrance of the tent of meeting.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":29},{"ref":"Leviticus 15:30","short":"Lev 15:30","text":"And the priest shall use one for a sin offering and the other for a burnt offering. And the priest shall make atonement for her before the LORD for her unclean discharge.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":30},{"ref":"Leviticus 15:31","short":"Lev 15:31","text":"“Thus you shall keep the people of Israel separate from their uncleanness, lest they die in their uncleanness by defiling my tabernacle that is in their midst.”","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":31},{"ref":"Leviticus 15:32","short":"Lev 15:32","text":"This is the law for him who has a discharge and for him who has an emission of semen, becoming unclean thereby;","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":32},{"ref":"Leviticus 15:33","short":"Lev 15:33","text":"also for her who is unwell with her menstrual impurity, that is, for anyone, male or female, who has a discharge, and for the man who lies with a woman who is unclean.","url":"ot/leviticus/Leviticus_15.html","book":"Leviticus","ch":15,"v":33},{"ref":"Leviticus 16:1","short":"Lev 16:1","text":"The LORD spoke to Moses after the death of the two sons of Aaron, when they drew near before the LORD and died,","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":1},{"ref":"Leviticus 16:2","short":"Lev 16:2","text":"and the LORD said to Moses, “Tell Aaron your brother not to come at any time into the Holy Place inside the veil, before the mercy seat that is on the ark, so that he may not die. For I will appear in the cloud over the mercy seat.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":2},{"ref":"Leviticus 16:3","short":"Lev 16:3","text":"But in this way Aaron shall come into the Holy Place: with a bull from the herd for a sin offering and a ram for a burnt offering.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":3},{"ref":"Leviticus 16:4","short":"Lev 16:4","text":"He shall put on the holy linen coat and shall have the linen undergarment on his body, and he shall tie the linen sash around his waist, and wear the linen turban; these are the holy garments. He shall bathe his body in water and then put them on.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":4},{"ref":"Leviticus 16:5","short":"Lev 16:5","text":"And he shall take from the congregation of the people of Israel two male goats for a sin offering, and one ram for a burnt offering.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":5},{"ref":"Leviticus 16:6","short":"Lev 16:6","text":"“Aaron shall offer the bull as a sin offering for himself and shall make atonement for himself and for his house.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":6},{"ref":"Leviticus 16:7","short":"Lev 16:7","text":"Then he shall take the two goats and set them before the LORD at the entrance of the tent of meeting.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":7},{"ref":"Leviticus 16:8","short":"Lev 16:8","text":"And Aaron shall cast lots over the two goats, one lot for the LORD and the other lot for Azazel.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":8},{"ref":"Leviticus 16:9","short":"Lev 16:9","text":"And Aaron shall present the goat on which the lot fell for the LORD and use it as a sin offering,","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":9},{"ref":"Leviticus 16:10","short":"Lev 16:10","text":"but the goat on which the lot fell for Azazel shall be presented alive before the LORD to make atonement over it, that it may be sent away into the wilderness to Azazel.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":10},{"ref":"Leviticus 16:11","short":"Lev 16:11","text":"“Aaron shall present the bull as a sin offering for himself, and shall make atonement for himself and for his house. He shall kill the bull as a sin offering for himself.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":11},{"ref":"Leviticus 16:12","short":"Lev 16:12","text":"And he shall take a censer full of coals of fire from the altar before the LORD, and two handfuls of sweet incense beaten small, and he shall bring it inside the veil","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":12},{"ref":"Leviticus 16:13","short":"Lev 16:13","text":"and put the incense on the fire before the LORD, that the cloud of the incense may cover the mercy seat that is over the testimony, so that he does not die.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":13},{"ref":"Leviticus 16:14","short":"Lev 16:14","text":"And he shall take some of the blood of the bull and sprinkle it with his finger on the front of the mercy seat on the east side, and in front of the mercy seat he shall sprinkle some of the blood with his finger seven times.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":14},{"ref":"Leviticus 16:15","short":"Lev 16:15","text":"“Then he shall kill the goat of the sin offering that is for the people and bring its blood inside the veil and do with its blood as he did with the blood of the bull, sprinkling it over the mercy seat and in front of the mercy seat.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":15},{"ref":"Leviticus 16:16","short":"Lev 16:16","text":"Thus he shall make atonement for the Holy Place, because of the uncleannesses of the people of Israel and because of their transgressions, all their sins. And so he shall do for the tent of meeting, which dwells with them in the midst of their uncleannesses.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":16},{"ref":"Leviticus 16:17","short":"Lev 16:17","text":"No one may be in the tent of meeting from the time he enters to make atonement in the Holy Place until he comes out and has made atonement for himself and for his house and for all the assembly of Israel.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":17},{"ref":"Leviticus 16:18","short":"Lev 16:18","text":"Then he shall go out to the altar that is before the LORD and make atonement for it, and shall take some of the blood of the bull and some of the blood of the goat, and put it on the horns of the altar all around.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":18},{"ref":"Leviticus 16:19","short":"Lev 16:19","text":"And he shall sprinkle some of the blood on it with his finger seven times, and cleanse it and consecrate it from the uncleannesses of the people of Israel.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":19},{"ref":"Leviticus 16:20","short":"Lev 16:20","text":"“And when he has made an end of atoning for the Holy Place and the tent of meeting and the altar, he shall present the live goat.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":20},{"ref":"Leviticus 16:21","short":"Lev 16:21","text":"And Aaron shall lay both his hands on the head of the live goat, and confess over it all the iniquities of the people of Israel, and all their transgressions, all their sins. And he shall put them on the head of the goat and send it away into the wilderness by the hand of a man who is in readiness.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":21},{"ref":"Leviticus 16:22","short":"Lev 16:22","text":"The goat shall bear all their iniquities on itself to a remote area, and he shall let the goat go free in the wilderness.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":22},{"ref":"Leviticus 16:23","short":"Lev 16:23","text":"“Then Aaron shall come into the tent of meeting and shall take off the linen garments that he put on when he went into the Holy Place and shall leave them there.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":23},{"ref":"Leviticus 16:24","short":"Lev 16:24","text":"And he shall bathe his body in water in a holy place and put on his garments and come out and offer his burnt offering and the burnt offering of the people and make atonement for himself and for the people.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":24},{"ref":"Leviticus 16:25","short":"Lev 16:25","text":"And the fat of the sin offering he shall burn on the altar.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":25},{"ref":"Leviticus 16:26","short":"Lev 16:26","text":"And he who lets the goat go to Azazel shall wash his clothes and bathe his body in water, and afterward he may come into the camp.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":26},{"ref":"Leviticus 16:27","short":"Lev 16:27","text":"And the bull for the sin offering and the goat for the sin offering, whose blood was brought in to make atonement in the Holy Place, shall be carried outside the camp. Their skin and their flesh and their dung shall be burned up with fire.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":27},{"ref":"Leviticus 16:28","short":"Lev 16:28","text":"And he who burns them shall wash his clothes and bathe his body in water, and afterward he may come into the camp.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":28},{"ref":"Leviticus 16:29","short":"Lev 16:29","text":"“And it shall be a statute to you forever that in the seventh month, on the tenth day of the month, you shall afflict yourselves and shall do no work, either the native or the stranger who sojourns among you.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":29},{"ref":"Leviticus 16:30","short":"Lev 16:30","text":"For on this day shall atonement be made for you to cleanse you. You shall be clean before the LORD from all your sins.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":30},{"ref":"Leviticus 16:31","short":"Lev 16:31","text":"It is a Sabbath of solemn rest to you, and you shall afflict yourselves; it is a statute forever.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":31},{"ref":"Leviticus 16:32","short":"Lev 16:32","text":"And the priest who is anointed and consecrated as priest in his father’s place shall make atonement, wearing the holy linen garments.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":32},{"ref":"Leviticus 16:33","short":"Lev 16:33","text":"He shall make atonement for the holy sanctuary, and he shall make atonement for the tent of meeting and for the altar, and he shall make atonement for the priests and for all the people of the assembly.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":33},{"ref":"Leviticus 16:34","short":"Lev 16:34","text":"And this shall be a statute forever for you, that atonement may be made for the people of Israel once in the year because of all their sins.” And Aaron did as the LORD commanded Moses.","url":"ot/leviticus/Leviticus_16.html","book":"Leviticus","ch":16,"v":34},{"ref":"Leviticus 17:1","short":"Lev 17:1","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":1},{"ref":"Leviticus 17:2","short":"Lev 17:2","text":"“Speak to Aaron and his sons and to all the people of Israel and say to them, This is the thing that the LORD has commanded.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":2},{"ref":"Leviticus 17:3","short":"Lev 17:3","text":"If any one of the house of Israel kills an ox or a lamb or a goat in the camp, or kills it outside the camp,","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":3},{"ref":"Leviticus 17:4","short":"Lev 17:4","text":"and does not bring it to the entrance of the tent of meeting to offer it as a gift to the LORD in front of the tabernacle of the LORD, bloodguilt shall be imputed to that man. He has shed blood, and that man shall be cut off from among his people.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":4},{"ref":"Leviticus 17:5","short":"Lev 17:5","text":"This is to the end that the people of Israel may bring their sacrifices that they sacrifice in the open field, that they may bring them to the LORD, to the priest at the entrance of the tent of meeting, and sacrifice them as sacrifices of peace offerings to the LORD.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":5},{"ref":"Leviticus 17:6","short":"Lev 17:6","text":"And the priest shall throw the blood on the altar of the LORD at the entrance of the tent of meeting and burn the fat for a pleasing aroma to the LORD.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":6},{"ref":"Leviticus 17:7","short":"Lev 17:7","text":"So they shall no more sacrifice their sacrifices to goat demons, after whom they whore. This shall be a statute forever for them throughout their generations.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":7},{"ref":"Leviticus 17:8","short":"Lev 17:8","text":"“And you shall say to them, Any one of the house of Israel, or of the strangers who sojourn among them, who offers a burnt offering or sacrifice","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":8},{"ref":"Leviticus 17:9","short":"Lev 17:9","text":"and does not bring it to the entrance of the tent of meeting to offer it to the LORD, that man shall be cut off from his people.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":9},{"ref":"Leviticus 17:10","short":"Lev 17:10","text":"“If any one of the house of Israel or of the strangers who sojourn among them eats any blood, I will set my face against that person who eats blood and will cut him off from among his people.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":10},{"ref":"Leviticus 17:11","short":"Lev 17:11","text":"For the life of the flesh is in the blood, and I have given it for you on the altar to make atonement for your souls, for it is the blood that makes atonement by the life.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":11},{"ref":"Leviticus 17:12","short":"Lev 17:12","text":"Therefore I have said to the people of Israel, No person among you shall eat blood, neither shall any stranger who sojourns among you eat blood.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":12},{"ref":"Leviticus 17:13","short":"Lev 17:13","text":"“Any one also of the people of Israel, or of the strangers who sojourn among them, who takes in hunting any beast or bird that may be eaten shall pour out its blood and cover it with earth.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":13},{"ref":"Leviticus 17:14","short":"Lev 17:14","text":"For the life of every creature is its blood: its blood is its life. Therefore I have said to the people of Israel, You shall not eat the blood of any creature, for the life of every creature is its blood. Whoever eats it shall be cut off.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":14},{"ref":"Leviticus 17:15","short":"Lev 17:15","text":"And every person who eats what dies of itself or what is torn by beasts, whether he is a native or a sojourner, shall wash his clothes and bathe himself in water and be unclean until the evening; then he shall be clean.","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":15},{"ref":"Leviticus 17:16","short":"Lev 17:16","text":"But if he does not wash them or bathe his flesh, he shall bear his iniquity.”","url":"ot/leviticus/Leviticus_17.html","book":"Leviticus","ch":17,"v":16},{"ref":"Leviticus 18:1","short":"Lev 18:1","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":1},{"ref":"Leviticus 18:2","short":"Lev 18:2","text":"“Speak to the people of Israel and say to them, I am the LORD your God.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":2},{"ref":"Leviticus 18:3","short":"Lev 18:3","text":"You shall not do as they do in the land of Egypt, where you lived, and you shall not do as they do in the land of Canaan, to which I am bringing you. You shall not walk in their statutes.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":3},{"ref":"Leviticus 18:4","short":"Lev 18:4","text":"You shall follow my rules and keep my statutes and walk in them. I am the LORD your God.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":4},{"ref":"Leviticus 18:5","short":"Lev 18:5","text":"You shall therefore keep my statutes and my rules; if a person does them, he shall live by them: I am the LORD.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":5},{"ref":"Leviticus 18:6","short":"Lev 18:6","text":"“None of you shall approach any one of his close relatives to uncover nakedness. I am the LORD.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":6},{"ref":"Leviticus 18:7","short":"Lev 18:7","text":"You shall not uncover the nakedness of your father, which is the nakedness of your mother; she is your mother, you shall not uncover her nakedness.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":7},{"ref":"Leviticus 18:8","short":"Lev 18:8","text":"You shall not uncover the nakedness of your father’s wife; it is your father’s nakedness.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":8},{"ref":"Leviticus 18:9","short":"Lev 18:9","text":"You shall not uncover the nakedness of your sister, your father’s daughter or your mother’s daughter, whether brought up in the family or in another home.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":9},{"ref":"Leviticus 18:10","short":"Lev 18:10","text":"You shall not uncover the nakedness of your son’s daughter or of your daughter’s daughter, for their nakedness is your own nakedness.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":10},{"ref":"Leviticus 18:11","short":"Lev 18:11","text":"You shall not uncover the nakedness of your father’s wife’s daughter, brought up in your father’s family, since she is your sister.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":11},{"ref":"Leviticus 18:12","short":"Lev 18:12","text":"You shall not uncover the nakedness of your father’s sister; she is your father’s relative.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":12},{"ref":"Leviticus 18:13","short":"Lev 18:13","text":"You shall not uncover the nakedness of your mother’s sister, for she is your mother’s relative.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":13},{"ref":"Leviticus 18:14","short":"Lev 18:14","text":"You shall not uncover the nakedness of your father’s brother, that is, you shall not approach his wife; she is your aunt.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":14},{"ref":"Leviticus 18:15","short":"Lev 18:15","text":"You shall not uncover the nakedness of your daughter-in-law; she is your son’s wife, you shall not uncover her nakedness.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":15},{"ref":"Leviticus 18:16","short":"Lev 18:16","text":"You shall not uncover the nakedness of your brother’s wife; it is your brother’s nakedness.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":16},{"ref":"Leviticus 18:17","short":"Lev 18:17","text":"You shall not uncover the nakedness of a woman and of her daughter, and you shall not take her son’s daughter or her daughter’s daughter to uncover her nakedness; they are relatives; it is depravity.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":17},{"ref":"Leviticus 18:18","short":"Lev 18:18","text":"And you shall not take a woman as a rival wife to her sister, uncovering her nakedness while her sister is still alive.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":18},{"ref":"Leviticus 18:19","short":"Lev 18:19","text":"“You shall not approach a woman to uncover her nakedness while she is in her menstrual uncleanness.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":19},{"ref":"Leviticus 18:20","short":"Lev 18:20","text":"And you shall not lie sexually with your neighbor’s wife and so make yourself unclean with her.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":20},{"ref":"Leviticus 18:21","short":"Lev 18:21","text":"You shall not give any of your children to offer them to Molech, and so profane the name of your God: I am the LORD.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":21},{"ref":"Leviticus 18:22","short":"Lev 18:22","text":"You shall not lie with a male as with a woman; it is an abomination.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":22},{"ref":"Leviticus 18:23","short":"Lev 18:23","text":"And you shall not lie with any animal and so make yourself unclean with it, neither shall any woman give herself to an animal to lie with it: it is perversion.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":23},{"ref":"Leviticus 18:24","short":"Lev 18:24","text":"“Do not make yourselves unclean by any of these things, for by all these the nations I am driving out before you have become unclean,","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":24},{"ref":"Leviticus 18:25","short":"Lev 18:25","text":"and the land became unclean, so that I punished its iniquity, and the land vomited out its inhabitants.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":25},{"ref":"Leviticus 18:26","short":"Lev 18:26","text":"But you shall keep my statutes and my rules and do none of these abominations, either the native or the stranger who sojourns among you","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":26},{"ref":"Leviticus 18:27","short":"Lev 18:27","text":"(for the people of the land, who were before you, did all of these abominations, so that the land became unclean),","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":27},{"ref":"Leviticus 18:28","short":"Lev 18:28","text":"lest the land vomit you out when you make it unclean, as it vomited out the nation that was before you.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":28},{"ref":"Leviticus 18:29","short":"Lev 18:29","text":"For everyone who does any of these abominations, the persons who do them shall be cut off from among their people.","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":29},{"ref":"Leviticus 18:30","short":"Lev 18:30","text":"So keep my charge never to practice any of these abominable customs that were practiced before you, and never to make yourselves unclean by them: I am the LORD your God.”","url":"ot/leviticus/Leviticus_18.html","book":"Leviticus","ch":18,"v":30},{"ref":"Leviticus 19:1","short":"Lev 19:1","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":1},{"ref":"Leviticus 19:2","short":"Lev 19:2","text":"“Speak to all the congregation of the people of Israel and say to them, You shall be holy, for I the LORD your God am holy.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":2},{"ref":"Leviticus 19:3","short":"Lev 19:3","text":"Every one of you shall revere his mother and his father, and you shall keep my Sabbaths: I am the LORD your God.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":3},{"ref":"Leviticus 19:4","short":"Lev 19:4","text":"Do not turn to idols or make for yourselves any gods of cast metal: I am the LORD your God.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":4},{"ref":"Leviticus 19:5","short":"Lev 19:5","text":"“When you offer a sacrifice of peace offerings to the LORD, you shall offer it so that you may be accepted.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":5},{"ref":"Leviticus 19:6","short":"Lev 19:6","text":"It shall be eaten the same day you offer it or on the day after, and anything left over until the third day shall be burned up with fire.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":6},{"ref":"Leviticus 19:7","short":"Lev 19:7","text":"If it is eaten at all on the third day, it is tainted; it will not be accepted,","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":7},{"ref":"Leviticus 19:8","short":"Lev 19:8","text":"and everyone who eats it shall bear his iniquity, because he has profaned what is holy to the LORD, and that person shall be cut off from his people.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":8},{"ref":"Leviticus 19:9","short":"Lev 19:9","text":"“When you reap the harvest of your land, you shall not reap your field right up to its edge, neither shall you gather the gleanings after your harvest.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":9},{"ref":"Leviticus 19:10","short":"Lev 19:10","text":"And you shall not strip your vineyard bare, neither shall you gather the fallen grapes of your vineyard. You shall leave them for the poor and for the sojourner: I am the LORD your God.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":10},{"ref":"Leviticus 19:11","short":"Lev 19:11","text":"“You shall not steal; you shall not deal falsely; you shall not lie to one another.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":11},{"ref":"Leviticus 19:12","short":"Lev 19:12","text":"You shall not swear by my name falsely, and so profane the name of your God: I am the LORD.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":12},{"ref":"Leviticus 19:13","short":"Lev 19:13","text":"“You shall not oppress your neighbor or rob him. The wages of a hired worker shall not remain with you all night until the morning.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":13},{"ref":"Leviticus 19:14","short":"Lev 19:14","text":"You shall not curse the deaf or put a stumbling block before the blind, but you shall fear your God: I am the LORD.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":14},{"ref":"Leviticus 19:15","short":"Lev 19:15","text":"“You shall do no injustice in court. You shall not be partial to the poor or defer to the great, but in righteousness shall you judge your neighbor.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":15},{"ref":"Leviticus 19:16","short":"Lev 19:16","text":"You shall not go around as a slanderer among your people, and you shall not stand up against the life of your neighbor: I am the LORD.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":16},{"ref":"Leviticus 19:17","short":"Lev 19:17","text":"“You shall not hate your brother in your heart, but you shall reason frankly with your neighbor, lest you incur sin because of him.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":17},{"ref":"Leviticus 19:18","short":"Lev 19:18","text":"You shall not take vengeance or bear a grudge against the sons of your own people, but you shall love your neighbor as yourself: I am the LORD.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":18},{"ref":"Leviticus 19:19","short":"Lev 19:19","text":"“You shall keep my statutes. You shall not let your cattle breed with a different kind. You shall not sow your field with two kinds of seed, nor shall you wear a garment of cloth made of two kinds of material.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":19},{"ref":"Leviticus 19:20","short":"Lev 19:20","text":"“If a man lies sexually with a woman who is a slave, assigned to another man and not yet ransomed or given her freedom, a distinction shall be made. They shall not be put to death, because she was not free;","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":20},{"ref":"Leviticus 19:21","short":"Lev 19:21","text":"but he shall bring his compensation to the LORD, to the entrance of the tent of meeting, a ram for a guilt offering.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":21},{"ref":"Leviticus 19:22","short":"Lev 19:22","text":"And the priest shall make atonement for him with the ram of the guilt offering before the LORD for his sin that he has committed, and he shall be forgiven for the sin that he has committed.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":22},{"ref":"Leviticus 19:23","short":"Lev 19:23","text":"“When you come into the land and plant any kind of tree for food, then you shall regard its fruit as forbidden. Three years it shall be forbidden to you; it must not be eaten.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":23},{"ref":"Leviticus 19:24","short":"Lev 19:24","text":"And in the fourth year all its fruit shall be holy, an offering of praise to the LORD.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":24},{"ref":"Leviticus 19:25","short":"Lev 19:25","text":"But in the fifth year you may eat of its fruit, to increase its yield for you: I am the LORD your God.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":25},{"ref":"Leviticus 19:26","short":"Lev 19:26","text":"“You shall not eat any flesh with the blood in it. You shall not interpret omens or tell fortunes.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":26},{"ref":"Leviticus 19:27","short":"Lev 19:27","text":"You shall not round off the hair on your temples or mar the edges of your beard.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":27},{"ref":"Leviticus 19:28","short":"Lev 19:28","text":"You shall not make any cuts on your body for the dead or tattoo yourselves: I am the LORD.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":28},{"ref":"Leviticus 19:29","short":"Lev 19:29","text":"“Do not profane your daughter by making her a prostitute, lest the land fall into prostitution and the land become full of depravity.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":29},{"ref":"Leviticus 19:30","short":"Lev 19:30","text":"You shall keep my Sabbaths and reverence my sanctuary: I am the LORD.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":30},{"ref":"Leviticus 19:31","short":"Lev 19:31","text":"“Do not turn to mediums or necromancers; do not seek them out, and so make yourselves unclean by them: I am the LORD your God.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":31},{"ref":"Leviticus 19:32","short":"Lev 19:32","text":"“You shall stand up before the gray head and honor the face of an old man, and you shall fear your God: I am the LORD.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":32},{"ref":"Leviticus 19:33","short":"Lev 19:33","text":"“When a stranger sojourns with you in your land, you shall not do him wrong.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":33},{"ref":"Leviticus 19:34","short":"Lev 19:34","text":"You shall treat the stranger who sojourns with you as the native among you, and you shall love him as yourself, for you were strangers in the land of Egypt: I am the LORD your God.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":34},{"ref":"Leviticus 19:35","short":"Lev 19:35","text":"“You shall do no wrong in judgment, in measures of length or weight or quantity.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":35},{"ref":"Leviticus 19:36","short":"Lev 19:36","text":"You shall have just balances, just weights, a just ephah, and a just hin: I am the LORD your God, who brought you out of the land of Egypt.","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":36},{"ref":"Leviticus 19:37","short":"Lev 19:37","text":"And you shall observe all my statutes and all my rules, and do them: I am the LORD.”","url":"ot/leviticus/Leviticus_19.html","book":"Leviticus","ch":19,"v":37},{"ref":"Leviticus 20:1","short":"Lev 20:1","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":1},{"ref":"Leviticus 20:2","short":"Lev 20:2","text":"“Say to the people of Israel, Any one of the people of Israel or of the strangers who sojourn in Israel who gives any of his children to Molech shall surely be put to death. The people of the land shall stone him with stones.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":2},{"ref":"Leviticus 20:3","short":"Lev 20:3","text":"I myself will set my face against that man and will cut him off from among his people, because he has given one of his children to Molech, to make my sanctuary unclean and to profane my holy name.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":3},{"ref":"Leviticus 20:4","short":"Lev 20:4","text":"And if the people of the land do at all close their eyes to that man when he gives one of his children to Molech, and do not put him to death,","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":4},{"ref":"Leviticus 20:5","short":"Lev 20:5","text":"then I will set my face against that man and against his clan and will cut them off from among their people, him and all who follow him in whoring after Molech.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":5},{"ref":"Leviticus 20:6","short":"Lev 20:6","text":"“If a person turns to mediums and necromancers, whoring after them, I will set my face against that person and will cut him off from among his people.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":6},{"ref":"Leviticus 20:7","short":"Lev 20:7","text":"Consecrate yourselves, therefore, and be holy, for I am the LORD your God.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":7},{"ref":"Leviticus 20:8","short":"Lev 20:8","text":"Keep my statutes and do them; I am the LORD who sanctifies you.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":8},{"ref":"Leviticus 20:9","short":"Lev 20:9","text":"For anyone who curses his father or his mother shall surely be put to death; he has cursed his father or his mother; his blood is upon him.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":9},{"ref":"Leviticus 20:10","short":"Lev 20:10","text":"“If a man commits adultery with the wife of his neighbor, both the adulterer and the adulteress shall surely be put to death.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":10},{"ref":"Leviticus 20:11","short":"Lev 20:11","text":"If a man lies with his father’s wife, he has uncovered his father’s nakedness; both of them shall surely be put to death; their blood is upon them.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":11},{"ref":"Leviticus 20:12","short":"Lev 20:12","text":"If a man lies with his daughter-in-law, both of them shall surely be put to death; they have committed perversion; their blood is upon them.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":12},{"ref":"Leviticus 20:13","short":"Lev 20:13","text":"If a man lies with a male as with a woman, both of them have committed an abomination; they shall surely be put to death; their blood is upon them.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":13},{"ref":"Leviticus 20:14","short":"Lev 20:14","text":"If a man takes a woman and her mother also, it is depravity; he and they shall be burned with fire, that there may be no depravity among you.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":14},{"ref":"Leviticus 20:15","short":"Lev 20:15","text":"If a man lies with an animal, he shall surely be put to death, and you shall kill the animal.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":15},{"ref":"Leviticus 20:16","short":"Lev 20:16","text":"If a woman approaches any animal and lies with it, you shall kill the woman and the animal; they shall surely be put to death; their blood is upon them.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":16},{"ref":"Leviticus 20:17","short":"Lev 20:17","text":"“If a man takes his sister, a daughter of his father or a daughter of his mother, and sees her nakedness, and she sees his nakedness, it is a disgrace, and they shall be cut off in the sight of the children of their people. He has uncovered his sister’s nakedness, and he shall bear his iniquity.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":17},{"ref":"Leviticus 20:18","short":"Lev 20:18","text":"If a man lies with a woman during her menstrual period and uncovers her nakedness, he has made naked her fountain, and she has uncovered the fountain of her blood. Both of them shall be cut off from among their people.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":18},{"ref":"Leviticus 20:19","short":"Lev 20:19","text":"You shall not uncover the nakedness of your mother’s sister or of your father’s sister, for that is to make naked one’s relative; they shall bear their iniquity.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":19},{"ref":"Leviticus 20:20","short":"Lev 20:20","text":"If a man lies with his uncle’s wife, he has uncovered his uncle’s nakedness; they shall bear their sin; they shall die childless.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":20},{"ref":"Leviticus 20:21","short":"Lev 20:21","text":"If a man takes his brother’s wife, it is impurity. He has uncovered his brother’s nakedness; they shall be childless.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":21},{"ref":"Leviticus 20:22","short":"Lev 20:22","text":"“You shall therefore keep all my statutes and all my rules and do them, that the land where I am bringing you to live may not vomit you out.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":22},{"ref":"Leviticus 20:23","short":"Lev 20:23","text":"And you shall not walk in the customs of the nation that I am driving out before you, for they did all these things, and therefore I detested them.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":23},{"ref":"Leviticus 20:24","short":"Lev 20:24","text":"But I have said to you, ‘You shall inherit their land, and I will give it to you to possess, a land flowing with milk and honey.’ I am the LORD your God, who has separated you from the peoples.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":24},{"ref":"Leviticus 20:25","short":"Lev 20:25","text":"You shall therefore separate the clean beast from the unclean, and the unclean bird from the clean. You shall not make yourselves detestable by beast or by bird or by anything with which the ground crawls, which I have set apart for you to hold unclean.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":25},{"ref":"Leviticus 20:26","short":"Lev 20:26","text":"You shall be holy to me, for I the LORD am holy and have separated you from the peoples, that you should be mine.","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":26},{"ref":"Leviticus 20:27","short":"Lev 20:27","text":"“A man or a woman who is a medium or a necromancer shall surely be put to death. They shall be stoned with stones; their blood shall be upon them.”","url":"ot/leviticus/Leviticus_20.html","book":"Leviticus","ch":20,"v":27},{"ref":"Leviticus 21:1","short":"Lev 21:1","text":"And the LORD said to Moses, “Speak to the priests, the sons of Aaron, and say to them, No one shall make himself unclean for the dead among his people,","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":1},{"ref":"Leviticus 21:2","short":"Lev 21:2","text":"except for his closest relatives, his mother, his father, his son, his daughter, his brother,","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":2},{"ref":"Leviticus 21:3","short":"Lev 21:3","text":"or his virgin sister (who is near to him because she has had no husband; for her he may make himself unclean).","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":3},{"ref":"Leviticus 21:4","short":"Lev 21:4","text":"He shall not make himself unclean as a husband among his people and so profane himself.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":4},{"ref":"Leviticus 21:5","short":"Lev 21:5","text":"They shall not make bald patches on their heads, nor shave off the edges of their beards, nor make any cuts on their body.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":5},{"ref":"Leviticus 21:6","short":"Lev 21:6","text":"They shall be holy to their God and not profane the name of their God. For they offer the LORD’s food offerings, the bread of their God; therefore they shall be holy.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":6},{"ref":"Leviticus 21:7","short":"Lev 21:7","text":"They shall not marry a prostitute or a woman who has been defiled, neither shall they marry a woman divorced from her husband, for the priest is holy to his God.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":7},{"ref":"Leviticus 21:8","short":"Lev 21:8","text":"You shall sanctify him, for he offers the bread of your God. He shall be holy to you, for I, the LORD, who sanctify you, am holy.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":8},{"ref":"Leviticus 21:9","short":"Lev 21:9","text":"And the daughter of any priest, if she profanes herself by whoring, profanes her father; she shall be burned with fire.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":9},{"ref":"Leviticus 21:10","short":"Lev 21:10","text":"“The priest who is chief among his brothers, on whose head the anointing oil is poured and who has been consecrated to wear the garments, shall not let the hair of his head hang loose nor tear his clothes.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":10},{"ref":"Leviticus 21:11","short":"Lev 21:11","text":"He shall not go in to any dead bodies nor make himself unclean, even for his father or for his mother.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":11},{"ref":"Leviticus 21:12","short":"Lev 21:12","text":"He shall not go out of the sanctuary, lest he profane the sanctuary of his God, for the consecration of the anointing oil of his God is on him: I am the LORD.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":12},{"ref":"Leviticus 21:13","short":"Lev 21:13","text":"And he shall take a wife in her virginity.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":13},{"ref":"Leviticus 21:14","short":"Lev 21:14","text":"A widow, or a divorced woman, or a woman who has been defiled, or a prostitute, these he shall not marry. But he shall take as his wife a virgin of his own people,","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":14},{"ref":"Leviticus 21:15","short":"Lev 21:15","text":"that he may not profane his offspring among his people, for I am the LORD who sanctifies him.”","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":15},{"ref":"Leviticus 21:16","short":"Lev 21:16","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":16},{"ref":"Leviticus 21:17","short":"Lev 21:17","text":"“Speak to Aaron, saying, None of your offspring throughout their generations who has a blemish may approach to offer the bread of his God.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":17},{"ref":"Leviticus 21:18","short":"Lev 21:18","text":"For no one who has a blemish shall draw near, a man blind or lame, or one who has a mutilated face or a limb too long,","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":18},{"ref":"Leviticus 21:19","short":"Lev 21:19","text":"or a man who has an injured foot or an injured hand,","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":19},{"ref":"Leviticus 21:20","short":"Lev 21:20","text":"or a hunchback or a dwarf or a man with a defect in his sight or an itching disease or scabs or crushed testicles.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":20},{"ref":"Leviticus 21:21","short":"Lev 21:21","text":"No man of the offspring of Aaron the priest who has a blemish shall come near to offer the LORD’s food offerings; since he has a blemish, he shall not come near to offer the bread of his God.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":21},{"ref":"Leviticus 21:22","short":"Lev 21:22","text":"He may eat the bread of his God, both of the most holy and of the holy things,","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":22},{"ref":"Leviticus 21:23","short":"Lev 21:23","text":"but he shall not go through the veil or approach the altar, because he has a blemish, that he may not profane my sanctuaries, for I am the LORD who sanctifies them.”","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":23},{"ref":"Leviticus 21:24","short":"Lev 21:24","text":"So Moses spoke to Aaron and to his sons and to all the people of Israel.","url":"ot/leviticus/Leviticus_21.html","book":"Leviticus","ch":21,"v":24},{"ref":"Leviticus 22:1","short":"Lev 22:1","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":1},{"ref":"Leviticus 22:2","short":"Lev 22:2","text":"“Speak to Aaron and his sons so that they abstain from the holy things of the people of Israel, which they dedicate to me, so that they do not profane my holy name: I am the LORD.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":2},{"ref":"Leviticus 22:3","short":"Lev 22:3","text":"Say to them, ‘If any one of all your offspring throughout your generations approaches the holy things that the people of Israel dedicate to the LORD, while he has an uncleanness, that person shall be cut off from my presence: I am the LORD.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":3},{"ref":"Leviticus 22:4","short":"Lev 22:4","text":"None of the offspring of Aaron who has a leprous disease or a discharge may eat of the holy things until he is clean. Whoever touches anything that is unclean through contact with the dead or a man who has had an emission of semen,","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":4},{"ref":"Leviticus 22:5","short":"Lev 22:5","text":"and whoever touches a swarming thing by which he may be made unclean or a person from whom he may take uncleanness, whatever his uncleanness may be—","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":5},{"ref":"Leviticus 22:6","short":"Lev 22:6","text":"the person who touches such a thing shall be unclean until the evening and shall not eat of the holy things unless he has bathed his body in water.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":6},{"ref":"Leviticus 22:7","short":"Lev 22:7","text":"When the sun goes down he shall be clean, and afterward he may eat of the holy things, because they are his food.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":7},{"ref":"Leviticus 22:8","short":"Lev 22:8","text":"He shall not eat what dies of itself or is torn by beasts, and so make himself unclean by it: I am the LORD.’","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":8},{"ref":"Leviticus 22:9","short":"Lev 22:9","text":"They shall therefore keep my charge, lest they bear sin for it and die thereby when they profane it: I am the LORD who sanctifies them.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":9},{"ref":"Leviticus 22:10","short":"Lev 22:10","text":"“A lay person shall not eat of a holy thing; no foreign guest of the priest or hired worker shall eat of a holy thing,","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":10},{"ref":"Leviticus 22:11","short":"Lev 22:11","text":"but if a priest buys a slave as his property for money, the slave may eat of it, and anyone born in his house may eat of his food.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":11},{"ref":"Leviticus 22:12","short":"Lev 22:12","text":"If a priest’s daughter marries a layman, she shall not eat of the contribution of the holy things.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":12},{"ref":"Leviticus 22:13","short":"Lev 22:13","text":"But if a priest’s daughter is widowed or divorced and has no child and returns to her father’s house, as in her youth, she may eat of her father’s food; yet no lay person shall eat of it.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":13},{"ref":"Leviticus 22:14","short":"Lev 22:14","text":"And if anyone eats of a holy thing unintentionally, he shall add the fifth of its value to it and give the holy thing to the priest.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":14},{"ref":"Leviticus 22:15","short":"Lev 22:15","text":"They shall not profane the holy things of the people of Israel, which they contribute to the LORD,","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":15},{"ref":"Leviticus 22:16","short":"Lev 22:16","text":"and so cause them to bear iniquity and guilt, by eating their holy things: for I am the LORD who sanctifies them.”","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":16},{"ref":"Leviticus 22:17","short":"Lev 22:17","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":17},{"ref":"Leviticus 22:18","short":"Lev 22:18","text":"“Speak to Aaron and his sons and all the people of Israel and say to them, When any one of the house of Israel or of the sojourners in Israel presents a burnt offering as his offering, for any of their vows or freewill offerings that they offer to the LORD,","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":18},{"ref":"Leviticus 22:19","short":"Lev 22:19","text":"if it is to be accepted for you it shall be a male without blemish, of the bulls or the sheep or the goats.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":19},{"ref":"Leviticus 22:20","short":"Lev 22:20","text":"You shall not offer anything that has a blemish, for it will not be acceptable for you.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":20},{"ref":"Leviticus 22:21","short":"Lev 22:21","text":"And when anyone offers a sacrifice of peace offerings to the LORD to fulfill a vow or as a freewill offering from the herd or from the flock, to be accepted it must be perfect; there shall be no blemish in it.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":21},{"ref":"Leviticus 22:22","short":"Lev 22:22","text":"Animals blind or disabled or mutilated or having a discharge or an itch or scabs you shall not offer to the LORD or give them to the LORD as a food offering on the altar.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":22},{"ref":"Leviticus 22:23","short":"Lev 22:23","text":"You may present a bull or a lamb that has a part too long or too short for a freewill offering, but for a vow offering it cannot be accepted.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":23},{"ref":"Leviticus 22:24","short":"Lev 22:24","text":"Any animal that has its testicles bruised or crushed or torn or cut you shall not offer to the LORD; you shall not do it within your land,","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":24},{"ref":"Leviticus 22:25","short":"Lev 22:25","text":"neither shall you offer as the bread of your God any such animals gotten from a foreigner. Since there is a blemish in them, because of their mutilation, they will not be accepted for you.”","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":25},{"ref":"Leviticus 22:26","short":"Lev 22:26","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":26},{"ref":"Leviticus 22:27","short":"Lev 22:27","text":"“When an ox or sheep or goat is born, it shall remain seven days with its mother, and from the eighth day on it shall be acceptable as a food offering to the LORD.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":27},{"ref":"Leviticus 22:28","short":"Lev 22:28","text":"But you shall not kill an ox or a sheep and her young in one day.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":28},{"ref":"Leviticus 22:29","short":"Lev 22:29","text":"And when you sacrifice a sacrifice of thanksgiving to the LORD, you shall sacrifice it so that you may be accepted.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":29},{"ref":"Leviticus 22:30","short":"Lev 22:30","text":"It shall be eaten on the same day; you shall leave none of it until morning: I am the LORD.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":30},{"ref":"Leviticus 22:31","short":"Lev 22:31","text":"“So you shall keep my commandments and do them: I am the LORD.","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":31},{"ref":"Leviticus 22:32","short":"Lev 22:32","text":"And you shall not profane my holy name, that I may be sanctified among the people of Israel. I am the LORD who sanctifies you,","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":32},{"ref":"Leviticus 22:33","short":"Lev 22:33","text":"who brought you out of the land of Egypt to be your God: I am the LORD.”","url":"ot/leviticus/Leviticus_22.html","book":"Leviticus","ch":22,"v":33},{"ref":"Leviticus 23:1","short":"Lev 23:1","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":1},{"ref":"Leviticus 23:2","short":"Lev 23:2","text":"“Speak to the people of Israel and say to them, These are the appointed feasts of the LORD that you shall proclaim as holy convocations; they are my appointed feasts.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":2},{"ref":"Leviticus 23:3","short":"Lev 23:3","text":"“Six days shall work be done, but on the seventh day is a Sabbath of solemn rest, a holy convocation. You shall do no work. It is a Sabbath to the LORD in all your dwelling places.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":3},{"ref":"Leviticus 23:4","short":"Lev 23:4","text":"“These are the appointed feasts of the LORD, the holy convocations, which you shall proclaim at the time appointed for them.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":4},{"ref":"Leviticus 23:5","short":"Lev 23:5","text":"In the first month, on the fourteenth day of the month at twilight, is the LORD’s Passover.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":5},{"ref":"Leviticus 23:6","short":"Lev 23:6","text":"And on the fifteenth day of the same month is the Feast of Unleavened Bread to the LORD; for seven days you shall eat unleavened bread.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":6},{"ref":"Leviticus 23:7","short":"Lev 23:7","text":"On the first day you shall have a holy convocation; you shall not do any ordinary work.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":7},{"ref":"Leviticus 23:8","short":"Lev 23:8","text":"But you shall present a food offering to the LORD for seven days. On the seventh day is a holy convocation; you shall not do any ordinary work.”","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":8},{"ref":"Leviticus 23:9","short":"Lev 23:9","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":9},{"ref":"Leviticus 23:10","short":"Lev 23:10","text":"“Speak to the people of Israel and say to them, When you come into the land that I give you and reap its harvest, you shall bring the sheaf of the firstfruits of your harvest to the priest,","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":10},{"ref":"Leviticus 23:11","short":"Lev 23:11","text":"and he shall wave the sheaf before the LORD, so that you may be accepted. On the day after the Sabbath the priest shall wave it.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":11},{"ref":"Leviticus 23:12","short":"Lev 23:12","text":"And on the day when you wave the sheaf, you shall offer a male lamb a year old without blemish as a burnt offering to the LORD.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":12},{"ref":"Leviticus 23:13","short":"Lev 23:13","text":"And the grain offering with it shall be two tenths of an ephah of fine flour mixed with oil, a food offering to the LORD with a pleasing aroma, and the drink offering with it shall be of wine, a fourth of a hin.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":13},{"ref":"Leviticus 23:14","short":"Lev 23:14","text":"And you shall eat neither bread nor grain parched or fresh until this same day, until you have brought the offering of your God: it is a statute forever throughout your generations in all your dwellings.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":14},{"ref":"Leviticus 23:15","short":"Lev 23:15","text":"“You shall count seven full weeks from the day after the Sabbath, from the day that you brought the sheaf of the wave offering.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":15},{"ref":"Leviticus 23:16","short":"Lev 23:16","text":"You shall count fifty days to the day after the seventh Sabbath. Then you shall present a grain offering of new grain to the LORD.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":16},{"ref":"Leviticus 23:17","short":"Lev 23:17","text":"You shall bring from your dwelling places two loaves of bread to be waved, made of two tenths of an ephah. They shall be of fine flour, and they shall be baked with leaven, as firstfruits to the LORD.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":17},{"ref":"Leviticus 23:18","short":"Lev 23:18","text":"And you shall present with the bread seven lambs a year old without blemish, and one bull from the herd and two rams. They shall be a burnt offering to the LORD, with their grain offering and their drink offerings, a food offering with a pleasing aroma to the LORD.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":18},{"ref":"Leviticus 23:19","short":"Lev 23:19","text":"And you shall offer one male goat for a sin offering, and two male lambs a year old as a sacrifice of peace offerings.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":19},{"ref":"Leviticus 23:20","short":"Lev 23:20","text":"And the priest shall wave them with the bread of the firstfruits as a wave offering before the LORD, with the two lambs. They shall be holy to the LORD for the priest.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":20},{"ref":"Leviticus 23:21","short":"Lev 23:21","text":"And you shall make a proclamation on the same day. You shall hold a holy convocation. You shall not do any ordinary work. It is a statute forever in all your dwelling places throughout your generations.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":21},{"ref":"Leviticus 23:22","short":"Lev 23:22","text":"“And when you reap the harvest of your land, you shall not reap your field right up to its edge, nor shall you gather the gleanings after your harvest. You shall leave them for the poor and for the sojourner: I am the LORD your God.”","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":22},{"ref":"Leviticus 23:23","short":"Lev 23:23","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":23},{"ref":"Leviticus 23:24","short":"Lev 23:24","text":"“Speak to the people of Israel, saying, In the seventh month, on the first day of the month, you shall observe a day of solemn rest, a memorial proclaimed with blast of trumpets, a holy convocation.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":24},{"ref":"Leviticus 23:25","short":"Lev 23:25","text":"You shall not do any ordinary work, and you shall present a food offering to the LORD.”","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":25},{"ref":"Leviticus 23:26","short":"Lev 23:26","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":26},{"ref":"Leviticus 23:27","short":"Lev 23:27","text":"“Now on the tenth day of this seventh month is the Day of Atonement. It shall be for you a time of holy convocation, and you shall afflict yourselves and present a food offering to the LORD.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":27},{"ref":"Leviticus 23:28","short":"Lev 23:28","text":"And you shall not do any work on that very day, for it is a Day of Atonement, to make atonement for you before the LORD your God.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":28},{"ref":"Leviticus 23:29","short":"Lev 23:29","text":"For whoever is not afflicted on that very day shall be cut off from his people.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":29},{"ref":"Leviticus 23:30","short":"Lev 23:30","text":"And whoever does any work on that very day, that person I will destroy from among his people.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":30},{"ref":"Leviticus 23:31","short":"Lev 23:31","text":"You shall not do any work. It is a statute forever throughout your generations in all your dwelling places.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":31},{"ref":"Leviticus 23:32","short":"Lev 23:32","text":"It shall be to you a Sabbath of solemn rest, and you shall afflict yourselves. On the ninth day of the month beginning at evening, from evening to evening shall you keep your Sabbath.”","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":32},{"ref":"Leviticus 23:33","short":"Lev 23:33","text":"And the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":33},{"ref":"Leviticus 23:34","short":"Lev 23:34","text":"“Speak to the people of Israel, saying, On the fifteenth day of this seventh month and for seven days is the Feast of Booths to the LORD.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":34},{"ref":"Leviticus 23:35","short":"Lev 23:35","text":"On the first day shall be a holy convocation; you shall not do any ordinary work.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":35},{"ref":"Leviticus 23:36","short":"Lev 23:36","text":"For seven days you shall present food offerings to the LORD. On the eighth day you shall hold a holy convocation and present a food offering to the LORD. It is a solemn assembly; you shall not do any ordinary work.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":36},{"ref":"Leviticus 23:37","short":"Lev 23:37","text":"“These are the appointed feasts of the LORD, which you shall proclaim as times of holy convocation, for presenting to the LORD food offerings, burnt offerings and grain offerings, sacrifices and drink offerings, each on its proper day,","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":37},{"ref":"Leviticus 23:38","short":"Lev 23:38","text":"besides the LORD’s Sabbaths and besides your gifts and besides all your vow offerings and besides all your freewill offerings, which you give to the LORD.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":38},{"ref":"Leviticus 23:39","short":"Lev 23:39","text":"“On the fifteenth day of the seventh month, when you have gathered in the produce of the land, you shall celebrate the feast of the LORD seven days. On the first day shall be a solemn rest, and on the eighth day shall be a solemn rest.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":39},{"ref":"Leviticus 23:40","short":"Lev 23:40","text":"And you shall take on the first day the fruit of splendid trees, branches of palm trees and boughs of leafy trees and willows of the brook, and you shall rejoice before the LORD your God seven days.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":40},{"ref":"Leviticus 23:41","short":"Lev 23:41","text":"You shall celebrate it as a feast to the LORD for seven days in the year. It is a statute forever throughout your generations; you shall celebrate it in the seventh month.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":41},{"ref":"Leviticus 23:42","short":"Lev 23:42","text":"You shall dwell in booths for seven days. All native Israelites shall dwell in booths,","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":42},{"ref":"Leviticus 23:43","short":"Lev 23:43","text":"that your generations may know that I made the people of Israel dwell in booths when I brought them out of the land of Egypt: I am the LORD your God.”","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":43},{"ref":"Leviticus 23:44","short":"Lev 23:44","text":"Thus Moses declared to the people of Israel the appointed feasts of the LORD.","url":"ot/leviticus/Leviticus_23.html","book":"Leviticus","ch":23,"v":44},{"ref":"Leviticus 24:1","short":"Lev 24:1","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":1},{"ref":"Leviticus 24:2","short":"Lev 24:2","text":"“Command the people of Israel to bring you pure oil from beaten olives for the lamp, that a light may be kept burning regularly.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":2},{"ref":"Leviticus 24:3","short":"Lev 24:3","text":"Outside the veil of the testimony, in the tent of meeting, Aaron shall arrange it from evening to morning before the LORD regularly. It shall be a statute forever throughout your generations.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":3},{"ref":"Leviticus 24:4","short":"Lev 24:4","text":"He shall arrange the lamps on the lampstand of pure gold before the LORD regularly.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":4},{"ref":"Leviticus 24:5","short":"Lev 24:5","text":"“You shall take fine flour and bake twelve loaves from it; two tenths of an ephah shall be in each loaf.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":5},{"ref":"Leviticus 24:6","short":"Lev 24:6","text":"And you shall set them in two piles, six in a pile, on the table of pure gold before the LORD.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":6},{"ref":"Leviticus 24:7","short":"Lev 24:7","text":"And you shall put pure frankincense on each pile, that it may go with the bread as a memorial portion as a food offering to the LORD.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":7},{"ref":"Leviticus 24:8","short":"Lev 24:8","text":"Every Sabbath day Aaron shall arrange it before the LORD regularly; it is from the people of Israel as a covenant forever.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":8},{"ref":"Leviticus 24:9","short":"Lev 24:9","text":"And it shall be for Aaron and his sons, and they shall eat it in a holy place, since it is for him a most holy portion out of the LORD’s food offerings, a perpetual due.”","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":9},{"ref":"Leviticus 24:10","short":"Lev 24:10","text":"Now an Israelite woman’s son, whose father was an Egyptian, went out among the people of Israel. And the Israelite woman’s son and a man of Israel fought in the camp,","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":10},{"ref":"Leviticus 24:11","short":"Lev 24:11","text":"and the Israelite woman’s son blasphemed the Name, and cursed. Then they brought him to Moses. His mother’s name was Shelomith, the daughter of Dibri, of the tribe of Dan.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":11},{"ref":"Leviticus 24:12","short":"Lev 24:12","text":"And they put him in custody, till the will of the LORD should be clear to them.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":12},{"ref":"Leviticus 24:13","short":"Lev 24:13","text":"Then the LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":13},{"ref":"Leviticus 24:14","short":"Lev 24:14","text":"“Bring out of the camp the one who cursed, and let all who heard him lay their hands on his head, and let all the congregation stone him.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":14},{"ref":"Leviticus 24:15","short":"Lev 24:15","text":"And speak to the people of Israel, saying, Whoever curses his God shall bear his sin.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":15},{"ref":"Leviticus 24:16","short":"Lev 24:16","text":"Whoever blasphemes the name of the LORD shall surely be put to death. All the congregation shall stone him. The sojourner as well as the native, when he blasphemes the Name, shall be put to death.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":16},{"ref":"Leviticus 24:17","short":"Lev 24:17","text":"“Whoever takes a human life shall surely be put to death.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":17},{"ref":"Leviticus 24:18","short":"Lev 24:18","text":"Whoever takes an animal’s life shall make it good, life for life.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":18},{"ref":"Leviticus 24:19","short":"Lev 24:19","text":"If anyone injures his neighbor, as he has done it shall be done to him,","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":19},{"ref":"Leviticus 24:20","short":"Lev 24:20","text":"fracture for fracture, eye for eye, tooth for tooth; whatever injury he has given a person shall be given to him.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":20},{"ref":"Leviticus 24:21","short":"Lev 24:21","text":"Whoever kills an animal shall make it good, and whoever kills a person shall be put to death.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":21},{"ref":"Leviticus 24:22","short":"Lev 24:22","text":"You shall have the same rule for the sojourner and for the native, for I am the LORD your God.”","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":22},{"ref":"Leviticus 24:23","short":"Lev 24:23","text":"So Moses spoke to the people of Israel, and they brought out of the camp the one who had cursed and stoned him with stones. Thus the people of Israel did as the LORD commanded Moses.","url":"ot/leviticus/Leviticus_24.html","book":"Leviticus","ch":24,"v":23},{"ref":"Leviticus 25:1","short":"Lev 25:1","text":"The LORD spoke to Moses on Mount Sinai, saying,","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":1},{"ref":"Leviticus 25:2","short":"Lev 25:2","text":"“Speak to the people of Israel and say to them, When you come into the land that I give you, the land shall keep a Sabbath to the LORD.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":2},{"ref":"Leviticus 25:3","short":"Lev 25:3","text":"For six years you shall sow your field, and for six years you shall prune your vineyard and gather in its fruits,","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":3},{"ref":"Leviticus 25:4","short":"Lev 25:4","text":"but in the seventh year there shall be a Sabbath of solemn rest for the land, a Sabbath to the LORD. You shall not sow your field or prune your vineyard.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":4},{"ref":"Leviticus 25:5","short":"Lev 25:5","text":"You shall not reap what grows of itself in your harvest, or gather the grapes of your undressed vine. It shall be a year of solemn rest for the land.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":5},{"ref":"Leviticus 25:6","short":"Lev 25:6","text":"The Sabbath of the land shall provide food for you, for yourself and for your male and female slaves and for your hired worker and the sojourner who lives with you,","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":6},{"ref":"Leviticus 25:7","short":"Lev 25:7","text":"and for your cattle and for the wild animals that are in your land: all its yield shall be for food.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":7},{"ref":"Leviticus 25:8","short":"Lev 25:8","text":"“You shall count seven weeks of years, seven times seven years, so that the time of the seven weeks of years shall give you forty-nine years.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":8},{"ref":"Leviticus 25:9","short":"Lev 25:9","text":"Then you shall sound the loud trumpet on the tenth day of the seventh month. On the Day of Atonement you shall sound the trumpet throughout all your land.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":9},{"ref":"Leviticus 25:10","short":"Lev 25:10","text":"And you shall consecrate the fiftieth year, and proclaim liberty throughout the land to all its inhabitants. It shall be a jubilee for you, when each of you shall return to his property and each of you shall return to his clan.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":10},{"ref":"Leviticus 25:11","short":"Lev 25:11","text":"That fiftieth year shall be a jubilee for you; in it you shall neither sow nor reap what grows of itself nor gather the grapes from the undressed vines.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":11},{"ref":"Leviticus 25:12","short":"Lev 25:12","text":"For it is a jubilee. It shall be holy to you. You may eat the produce of the field.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":12},{"ref":"Leviticus 25:13","short":"Lev 25:13","text":"“In this year of jubilee each of you shall return to his property.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":13},{"ref":"Leviticus 25:14","short":"Lev 25:14","text":"And if you make a sale to your neighbor or buy from your neighbor, you shall not wrong one another.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":14},{"ref":"Leviticus 25:15","short":"Lev 25:15","text":"You shall pay your neighbor according to the number of years after the jubilee, and he shall sell to you according to the number of years for crops.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":15},{"ref":"Leviticus 25:16","short":"Lev 25:16","text":"If the years are many, you shall increase the price, and if the years are few, you shall reduce the price, for it is the number of the crops that he is selling to you.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":16},{"ref":"Leviticus 25:17","short":"Lev 25:17","text":"You shall not wrong one another, but you shall fear your God, for I am the LORD your God.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":17},{"ref":"Leviticus 25:18","short":"Lev 25:18","text":"“Therefore you shall do my statutes and keep my rules and perform them, and then you will dwell in the land securely.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":18},{"ref":"Leviticus 25:19","short":"Lev 25:19","text":"The land will yield its fruit, and you will eat your fill and dwell in it securely.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":19},{"ref":"Leviticus 25:20","short":"Lev 25:20","text":"And if you say, ‘What shall we eat in the seventh year, if we may not sow or gather in our crop?’","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":20},{"ref":"Leviticus 25:21","short":"Lev 25:21","text":"I will command my blessing on you in the sixth year, so that it will produce a crop sufficient for three years.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":21},{"ref":"Leviticus 25:22","short":"Lev 25:22","text":"When you sow in the eighth year, you will be eating some of the old crop; you shall eat the old until the ninth year, when its crop arrives.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":22},{"ref":"Leviticus 25:23","short":"Lev 25:23","text":"“The land shall not be sold in perpetuity, for the land is mine. For you are strangers and sojourners with me.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":23},{"ref":"Leviticus 25:24","short":"Lev 25:24","text":"And in all the country you possess, you shall allow a redemption of the land.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":24},{"ref":"Leviticus 25:25","short":"Lev 25:25","text":"“If your brother becomes poor and sells part of his property, then his nearest redeemer shall come and redeem what his brother has sold.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":25},{"ref":"Leviticus 25:26","short":"Lev 25:26","text":"If a man has no one to redeem it and then himself becomes prosperous and finds sufficient means to redeem it,","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":26},{"ref":"Leviticus 25:27","short":"Lev 25:27","text":"let him calculate the years since he sold it and pay back the balance to the man to whom he sold it, and then return to his property.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":27},{"ref":"Leviticus 25:28","short":"Lev 25:28","text":"But if he does not have sufficient means to recover it, then what he sold shall remain in the hand of the buyer until the year of jubilee. In the jubilee it shall be released, and he shall return to his property.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":28},{"ref":"Leviticus 25:29","short":"Lev 25:29","text":"“If a man sells a dwelling house in a walled city, he may redeem it within a year of its sale. For a full year he shall have the right of redemption.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":29},{"ref":"Leviticus 25:30","short":"Lev 25:30","text":"If it is not redeemed within a full year, then the house in the walled city shall belong in perpetuity to the buyer, throughout his generations; it shall not be released in the jubilee.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":30},{"ref":"Leviticus 25:31","short":"Lev 25:31","text":"But the houses of the villages that have no wall around them shall be classified with the fields of the land. They may be redeemed, and they shall be released in the jubilee.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":31},{"ref":"Leviticus 25:32","short":"Lev 25:32","text":"As for the cities of the Levites, the Levites may redeem at any time the houses in the cities they possess.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":32},{"ref":"Leviticus 25:33","short":"Lev 25:33","text":"And if one of the Levites exercises his right of redemption, then the house that was sold in a city they possess shall be released in the jubilee. For the houses in the cities of the Levites are their possession among the people of Israel.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":33},{"ref":"Leviticus 25:34","short":"Lev 25:34","text":"But the fields of pastureland belonging to their cities may not be sold, for that is their possession forever.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":34},{"ref":"Leviticus 25:35","short":"Lev 25:35","text":"“If your brother becomes poor and cannot maintain himself with you, you shall support him as though he were a stranger and a sojourner, and he shall live with you.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":35},{"ref":"Leviticus 25:36","short":"Lev 25:36","text":"Take no interest from him or profit, but fear your God, that your brother may live beside you.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":36},{"ref":"Leviticus 25:37","short":"Lev 25:37","text":"You shall not lend him your money at interest, nor give him your food for profit.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":37},{"ref":"Leviticus 25:38","short":"Lev 25:38","text":"I am the LORD your God, who brought you out of the land of Egypt to give you the land of Canaan, and to be your God.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":38},{"ref":"Leviticus 25:39","short":"Lev 25:39","text":"“If your brother becomes poor beside you and sells himself to you, you shall not make him serve as a slave:","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":39},{"ref":"Leviticus 25:40","short":"Lev 25:40","text":"he shall be with you as a hired worker and as a sojourner. He shall serve with you until the year of the jubilee.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":40},{"ref":"Leviticus 25:41","short":"Lev 25:41","text":"Then he shall go out from you, he and his children with him, and go back to his own clan and return to the possession of his fathers.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":41},{"ref":"Leviticus 25:42","short":"Lev 25:42","text":"For they are my servants, whom I brought out of the land of Egypt; they shall not be sold as slaves.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":42},{"ref":"Leviticus 25:43","short":"Lev 25:43","text":"You shall not rule over him ruthlessly but shall fear your God.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":43},{"ref":"Leviticus 25:44","short":"Lev 25:44","text":"As for your male and female slaves whom you may have: you may buy male and female slaves from among the nations that are around you.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":44},{"ref":"Leviticus 25:45","short":"Lev 25:45","text":"You may also buy from among the strangers who sojourn with you and their clans that are with you, who have been born in your land, and they may be your property.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":45},{"ref":"Leviticus 25:46","short":"Lev 25:46","text":"You may bequeath them to your sons after you to inherit as a possession forever. You may make slaves of them, but over your brothers the people of Israel you shall not rule, one over another ruthlessly.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":46},{"ref":"Leviticus 25:47","short":"Lev 25:47","text":"“If a stranger or sojourner with you becomes rich, and your brother beside him becomes poor and sells himself to the stranger or sojourner with you or to a member of the stranger’s clan,","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":47},{"ref":"Leviticus 25:48","short":"Lev 25:48","text":"then after he is sold he may be redeemed. One of his brothers may redeem him,","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":48},{"ref":"Leviticus 25:49","short":"Lev 25:49","text":"or his uncle or his cousin may redeem him, or a close relative from his clan may redeem him. Or if he grows rich he may redeem himself.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":49},{"ref":"Leviticus 25:50","short":"Lev 25:50","text":"He shall calculate with his buyer from the year when he sold himself to him until the year of jubilee, and the price of his sale shall vary with the number of years. The time he was with his owner shall be rated as the time of a hired worker.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":50},{"ref":"Leviticus 25:51","short":"Lev 25:51","text":"If there are still many years left, he shall pay proportionately for his redemption some of his sale price.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":51},{"ref":"Leviticus 25:52","short":"Lev 25:52","text":"If there remain but a few years until the year of jubilee, he shall calculate and pay for his redemption in proportion to his years of service.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":52},{"ref":"Leviticus 25:53","short":"Lev 25:53","text":"He shall treat him as a worker hired year by year. He shall not rule ruthlessly over him in your sight.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":53},{"ref":"Leviticus 25:54","short":"Lev 25:54","text":"And if he is not redeemed by these means, then he and his children with him shall be released in the year of jubilee.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":54},{"ref":"Leviticus 25:55","short":"Lev 25:55","text":"For it is to me that the people of Israel are servants. They are my servants whom I brought out of the land of Egypt: I am the LORD your God.","url":"ot/leviticus/Leviticus_25.html","book":"Leviticus","ch":25,"v":55},{"ref":"Leviticus 26:1","short":"Lev 26:1","text":"“You shall not make idols for yourselves or erect an image or pillar, and you shall not set up a figured stone in your land to bow down to it, for I am the LORD your God.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":1},{"ref":"Leviticus 26:2","short":"Lev 26:2","text":"You shall keep my Sabbaths and reverence my sanctuary: I am the LORD.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":2},{"ref":"Leviticus 26:3","short":"Lev 26:3","text":"“If you walk in my statutes and observe my commandments and do them,","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":3},{"ref":"Leviticus 26:4","short":"Lev 26:4","text":"then I will give you your rains in their season, and the land shall yield its increase, and the trees of the field shall yield their fruit.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":4},{"ref":"Leviticus 26:5","short":"Lev 26:5","text":"Your threshing shall last to the time of the grape harvest, and the grape harvest shall last to the time for sowing. And you shall eat your bread to the full and dwell in your land securely.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":5},{"ref":"Leviticus 26:6","short":"Lev 26:6","text":"I will give peace in the land, and you shall lie down, and none shall make you afraid. And I will remove harmful beasts from the land, and the sword shall not go through your land.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":6},{"ref":"Leviticus 26:7","short":"Lev 26:7","text":"You shall chase your enemies, and they shall fall before you by the sword.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":7},{"ref":"Leviticus 26:8","short":"Lev 26:8","text":"Five of you shall chase a hundred, and a hundred of you shall chase ten thousand, and your enemies shall fall before you by the sword.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":8},{"ref":"Leviticus 26:9","short":"Lev 26:9","text":"I will turn to you and make you fruitful and multiply you and will confirm my covenant with you.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":9},{"ref":"Leviticus 26:10","short":"Lev 26:10","text":"You shall eat old store long kept, and you shall clear out the old to make way for the new.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":10},{"ref":"Leviticus 26:11","short":"Lev 26:11","text":"I will make my dwelling among you, and my soul shall not abhor you.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":11},{"ref":"Leviticus 26:12","short":"Lev 26:12","text":"And I will walk among you and will be your God, and you shall be my people.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":12},{"ref":"Leviticus 26:13","short":"Lev 26:13","text":"I am the LORD your God, who brought you out of the land of Egypt, that you should not be their slaves. And I have broken the bars of your yoke and made you walk erect.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":13},{"ref":"Leviticus 26:14","short":"Lev 26:14","text":"“But if you will not listen to me and will not do all these commandments,","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":14},{"ref":"Leviticus 26:15","short":"Lev 26:15","text":"if you spurn my statutes, and if your soul abhors my rules, so that you will not do all my commandments, but break my covenant,","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":15},{"ref":"Leviticus 26:16","short":"Lev 26:16","text":"then I will do this to you: I will visit you with panic, with wasting disease and fever that consume the eyes and make the heart ache. And you shall sow your seed in vain, for your enemies shall eat it.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":16},{"ref":"Leviticus 26:17","short":"Lev 26:17","text":"I will set my face against you, and you shall be struck down before your enemies. Those who hate you shall rule over you, and you shall flee when none pursues you.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":17},{"ref":"Leviticus 26:18","short":"Lev 26:18","text":"And if in spite of this you will not listen to me, then I will discipline you again sevenfold for your sins,","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":18},{"ref":"Leviticus 26:19","short":"Lev 26:19","text":"and I will break the pride of your power, and I will make your heavens like iron and your earth like bronze.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":19},{"ref":"Leviticus 26:20","short":"Lev 26:20","text":"And your strength shall be spent in vain, for your land shall not yield its increase, and the trees of the land shall not yield their fruit.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":20},{"ref":"Leviticus 26:21","short":"Lev 26:21","text":"“Then if you walk contrary to me and will not listen to me, I will continue striking you, sevenfold for your sins.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":21},{"ref":"Leviticus 26:22","short":"Lev 26:22","text":"And I will let loose the wild beasts against you, which shall bereave you of your children and destroy your livestock and make you few in number, so that your roads shall be deserted.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":22},{"ref":"Leviticus 26:23","short":"Lev 26:23","text":"“And if by this discipline you are not turned to me but walk contrary to me,","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":23},{"ref":"Leviticus 26:24","short":"Lev 26:24","text":"then I also will walk contrary to you, and I myself will strike you sevenfold for your sins.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":24},{"ref":"Leviticus 26:25","short":"Lev 26:25","text":"And I will bring a sword upon you, that shall execute vengeance for the covenant. And if you gather within your cities, I will send pestilence among you, and you shall be delivered into the hand of the enemy.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":25},{"ref":"Leviticus 26:26","short":"Lev 26:26","text":"When I break your supply of bread, ten women shall bake your bread in a single oven and shall dole out your bread again by weight, and you shall eat and not be satisfied.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":26},{"ref":"Leviticus 26:27","short":"Lev 26:27","text":"“But if in spite of this you will not listen to me, but walk contrary to me,","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":27},{"ref":"Leviticus 26:28","short":"Lev 26:28","text":"then I will walk contrary to you in fury, and I myself will discipline you sevenfold for your sins.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":28},{"ref":"Leviticus 26:29","short":"Lev 26:29","text":"You shall eat the flesh of your sons, and you shall eat the flesh of your daughters.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":29},{"ref":"Leviticus 26:30","short":"Lev 26:30","text":"And I will destroy your high places and cut down your incense altars and cast your dead bodies upon the dead bodies of your idols, and my soul will abhor you.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":30},{"ref":"Leviticus 26:31","short":"Lev 26:31","text":"And I will lay your cities waste and will make your sanctuaries desolate, and I will not smell your pleasing aromas.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":31},{"ref":"Leviticus 26:32","short":"Lev 26:32","text":"And I myself will devastate the land, so that your enemies who settle in it shall be appalled at it.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":32},{"ref":"Leviticus 26:33","short":"Lev 26:33","text":"And I will scatter you among the nations, and I will unsheathe the sword after you, and your land shall be a desolation, and your cities shall be a waste.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":33},{"ref":"Leviticus 26:34","short":"Lev 26:34","text":"“Then the land shall enjoy its Sabbaths as long as it lies desolate, while you are in your enemies’ land; then the land shall rest, and enjoy its Sabbaths.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":34},{"ref":"Leviticus 26:35","short":"Lev 26:35","text":"As long as it lies desolate it shall have rest, the rest that it did not have on your Sabbaths when you were dwelling in it.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":35},{"ref":"Leviticus 26:36","short":"Lev 26:36","text":"And as for those of you who are left, I will send faintness into their hearts in the lands of their enemies. The sound of a driven leaf shall put them to flight, and they shall flee as one flees from the sword, and they shall fall when none pursues.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":36},{"ref":"Leviticus 26:37","short":"Lev 26:37","text":"They shall stumble over one another, as if to escape a sword, though none pursues. And you shall have no power to stand before your enemies.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":37},{"ref":"Leviticus 26:38","short":"Lev 26:38","text":"And you shall perish among the nations, and the land of your enemies shall eat you up.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":38},{"ref":"Leviticus 26:39","short":"Lev 26:39","text":"And those of you who are left shall rot away in your enemies’ lands because of their iniquity, and also because of the iniquities of their fathers they shall rot away like them.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":39},{"ref":"Leviticus 26:40","short":"Lev 26:40","text":"“But if they confess their iniquity and the iniquity of their fathers in their treachery that they committed against me, and also in walking contrary to me,","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":40},{"ref":"Leviticus 26:41","short":"Lev 26:41","text":"so that I walked contrary to them and brought them into the land of their enemies—if then their uncircumcised heart is humbled and they make amends for their iniquity,","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":41},{"ref":"Leviticus 26:42","short":"Lev 26:42","text":"then I will remember my covenant with Jacob, and I will remember my covenant with Isaac and my covenant with Abraham, and I will remember the land.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":42},{"ref":"Leviticus 26:43","short":"Lev 26:43","text":"But the land shall be abandoned by them and enjoy its Sabbaths while it lies desolate without them, and they shall make amends for their iniquity, because they spurned my rules and their soul abhorred my statutes.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":43},{"ref":"Leviticus 26:44","short":"Lev 26:44","text":"Yet for all that, when they are in the land of their enemies, I will not spurn them, neither will I abhor them so as to destroy them utterly and break my covenant with them, for I am the LORD their God.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":44},{"ref":"Leviticus 26:45","short":"Lev 26:45","text":"But I will for their sake remember the covenant with their forefathers, whom I brought out of the land of Egypt in the sight of the nations, that I might be their God: I am the LORD.”","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":45},{"ref":"Leviticus 26:46","short":"Lev 26:46","text":"These are the statutes and rules and laws that the LORD made between himself and the people of Israel through Moses on Mount Sinai.","url":"ot/leviticus/Leviticus_26.html","book":"Leviticus","ch":26,"v":46},{"ref":"Leviticus 27:1","short":"Lev 27:1","text":"The LORD spoke to Moses, saying,","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":1},{"ref":"Leviticus 27:2","short":"Lev 27:2","text":"“Speak to the people of Israel and say to them, If anyone makes a special vow to the LORD involving the valuation of persons,","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":2},{"ref":"Leviticus 27:3","short":"Lev 27:3","text":"then the valuation of a male from twenty years old up to sixty years old shall be fifty shekels of silver, according to the shekel of the sanctuary.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":3},{"ref":"Leviticus 27:4","short":"Lev 27:4","text":"If the person is a female, the valuation shall be thirty shekels.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":4},{"ref":"Leviticus 27:5","short":"Lev 27:5","text":"If the person is from five years old up to twenty years old, the valuation shall be for a male twenty shekels, and for a female ten shekels.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":5},{"ref":"Leviticus 27:6","short":"Lev 27:6","text":"If the person is from a month old up to five years old, the valuation shall be for a male five shekels of silver, and for a female the valuation shall be three shekels of silver.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":6},{"ref":"Leviticus 27:7","short":"Lev 27:7","text":"And if the person is sixty years old or over, then the valuation for a male shall be fifteen shekels, and for a female ten shekels.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":7},{"ref":"Leviticus 27:8","short":"Lev 27:8","text":"And if someone is too poor to pay the valuation, then he shall be made to stand before the priest, and the priest shall value him; the priest shall value him according to what the vower can afford.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":8},{"ref":"Leviticus 27:9","short":"Lev 27:9","text":"“If the vow is an animal that may be offered as an offering to the LORD, all of it that he gives to the LORD is holy.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":9},{"ref":"Leviticus 27:10","short":"Lev 27:10","text":"He shall not exchange it or make a substitute for it, good for bad, or bad for good; and if he does in fact substitute one animal for another, then both it and the substitute shall be holy.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":10},{"ref":"Leviticus 27:11","short":"Lev 27:11","text":"And if it is any unclean animal that may not be offered as an offering to the LORD, then he shall stand the animal before the priest,","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":11},{"ref":"Leviticus 27:12","short":"Lev 27:12","text":"and the priest shall value it as either good or bad; as the priest values it, so it shall be.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":12},{"ref":"Leviticus 27:13","short":"Lev 27:13","text":"But if he wishes to redeem it, he shall add a fifth to the valuation.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":13},{"ref":"Leviticus 27:14","short":"Lev 27:14","text":"“When a man dedicates his house as a holy gift to the LORD, the priest shall value it as either good or bad; as the priest values it, so it shall stand.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":14},{"ref":"Leviticus 27:15","short":"Lev 27:15","text":"And if the donor wishes to redeem his house, he shall add a fifth to the valuation price, and it shall be his.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":15},{"ref":"Leviticus 27:16","short":"Lev 27:16","text":"“If a man dedicates to the LORD part of the land that is his possession, then the valuation shall be in proportion to its seed. A homer of barley seed shall be valued at fifty shekels of silver.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":16},{"ref":"Leviticus 27:17","short":"Lev 27:17","text":"If he dedicates his field from the year of jubilee, the valuation shall stand,","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":17},{"ref":"Leviticus 27:18","short":"Lev 27:18","text":"but if he dedicates his field after the jubilee, then the priest shall calculate the price according to the years that remain until the year of jubilee, and a deduction shall be made from the valuation.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":18},{"ref":"Leviticus 27:19","short":"Lev 27:19","text":"And if he who dedicates the field wishes to redeem it, then he shall add a fifth to its valuation price, and it shall remain his.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":19},{"ref":"Leviticus 27:20","short":"Lev 27:20","text":"But if he does not wish to redeem the field, or if he has sold the field to another man, it shall not be redeemed anymore.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":20},{"ref":"Leviticus 27:21","short":"Lev 27:21","text":"But the field, when it is released in the jubilee, shall be a holy gift to the LORD, like a field that has been devoted. The priest shall be in possession of it.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":21},{"ref":"Leviticus 27:22","short":"Lev 27:22","text":"If he dedicates to the LORD a field that he has bought, which is not a part of his possession,","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":22},{"ref":"Leviticus 27:23","short":"Lev 27:23","text":"then the priest shall calculate the amount of the valuation for it up to the year of jubilee, and the man shall give the valuation on that day as a holy gift to the LORD.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":23},{"ref":"Leviticus 27:24","short":"Lev 27:24","text":"In the year of jubilee the field shall return to him from whom it was bought, to whom the land belongs as a possession.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":24},{"ref":"Leviticus 27:25","short":"Lev 27:25","text":"Every valuation shall be according to the shekel of the sanctuary: twenty gerahs shall make a shekel.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":25},{"ref":"Leviticus 27:26","short":"Lev 27:26","text":"“But a firstborn of animals, which as a firstborn belongs to the LORD, no man may dedicate; whether ox or sheep, it is the LORD’s.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":26},{"ref":"Leviticus 27:27","short":"Lev 27:27","text":"And if it is an unclean animal, then he shall buy it back at the valuation, and add a fifth to it; or, if it is not redeemed, it shall be sold at the valuation.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":27},{"ref":"Leviticus 27:28","short":"Lev 27:28","text":"“But no devoted thing that a man devotes to the LORD, of anything that he has, whether man or beast, or of his inherited field, shall be sold or redeemed; every devoted thing is most holy to the LORD.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":28},{"ref":"Leviticus 27:29","short":"Lev 27:29","text":"No one devoted, who is to be devoted for destruction from mankind, shall be ransomed; he shall surely be put to death.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":29},{"ref":"Leviticus 27:30","short":"Lev 27:30","text":"“Every tithe of the land, whether of the seed of the land or of the fruit of the trees, is the LORD’s; it is holy to the LORD.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":30},{"ref":"Leviticus 27:31","short":"Lev 27:31","text":"If a man wishes to redeem some of his tithe, he shall add a fifth to it.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":31},{"ref":"Leviticus 27:32","short":"Lev 27:32","text":"And every tithe of herds and flocks, every tenth animal of all that pass under the herdsman’s staff, shall be holy to the LORD.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":32},{"ref":"Leviticus 27:33","short":"Lev 27:33","text":"One shall not differentiate between good or bad, neither shall he make a substitute for it; and if he does substitute for it, then both it and the substitute shall be holy; it shall not be redeemed.”","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":33},{"ref":"Leviticus 27:34","short":"Lev 27:34","text":"These are the commandments that the LORD commanded Moses for the people of Israel on Mount Sinai.","url":"ot/leviticus/Leviticus_27.html","book":"Leviticus","ch":27,"v":34}];
if(!window.VERSES_ALL)window.VERSES_ALL=[];
window.VERSES_ALL=window.VERSES_ALL.concat(VERSES_LEVITICUS);
